function nodeChildren(nodes, parentId) {
    return (nodes || []).filter((n) => (n.parentId || null) === (parentId || null));
}
function findNode(nodes, id) {
    return (nodes || []).find((n) => String(n.id) === String(id)) || null;
}
function findNoteNodeByNoteId(noteId) {
    return (state.userNoteNodes || []).find((n) => n.type === "note" && String(n.noteId || "") === String(noteId || "")) || null;
}
function notesFolderNodes() {
    return (state.userNoteNodes || []).filter((n) => n?.type === "folder");
}
function noteNodesInFolder(folderId) {
    const id = folderId ? String(folderId) : "";
    return (state.userNoteNodes || []).filter((n) => n?.type === "note" && String(n.parentId || "") === id);
}
function noteNodesInFolderRecursive(folderId) {
    const rootId = folderId ? String(folderId) : "";
    const allNodes = state.userNoteNodes || [];
    const out = [];
    const stack = [rootId];
    while (stack.length) {
        const parent = stack.pop();
        const children = allNodes.filter((n) => String(n.parentId || "") === String(parent || ""));
        children.forEach((child) => {
            if (child.type === "folder") stack.push(String(child.id));
            if (child.type === "note" && child.noteId) out.push(child);
        });
    }
    const deduped = new Map();
    out.forEach((question) => {
        const key = canonicalSearchDedupeKey(question);
        const prev = deduped.get(key);
        if (!prev || (question.isCanonical && !prev.isCanonical)) {
            deduped.set(key, question);
        }
    });
    return [...deduped.values()];
}
function inferSubjectFromFolder(folderId) {
    if (!folderId) return "General";
    let cur = findNode(state.userNoteNodes || [], folderId);
    let hops = 0;
    while (cur?.parentId && hops < 40) {
        cur = findNode(state.userNoteNodes || [], cur.parentId);
        hops++;
    }
    return String(cur?.title || "General").trim() || "General";
}

async function createUserNoteNodeSafe(node) {
    try {
        const created = await createUserNoteNode(state.currentUser.uid, node);
        state.userNoteNodes = [...(state.userNoteNodes || []), created];
        return created;
    } catch (error) {
        console.error("Failed to persist note tree node:", error);
        const detail = error?.message || error?.details || error?.hint || "";
        const lower = String(detail || "").toLowerCase();
        if (lower.includes("user_note_nodes") || lower.includes("schema cache")) {
            showNotice("Could not save folder/notebook on server because the Supabase table `public.user_note_nodes` does not exist yet. Run the notes hierarchy SQL migration first.");
        } else {
            showNotice(detail ? `Could not save folder/notebook: ${detail}` : "Could not save folder/notebook to server. Please retry.");
        }
        throw error;
    }
}

async function bootstrapNotesTreeFromLegacyNotes() {
    if (!isLoggedIn() || !state.currentUser?.uid) return;
    const existingNodes = Array.isArray(state.userNoteNodes) ? state.userNoteNodes : [];
    const hasBackupFolder = existingNodes.some((node) => node?.type === "folder" && String(node.title || "").trim().toLowerCase() === "backup");
    const noteNodeIds = new Set(existingNodes.filter((node) => node?.type === "note" && node?.noteId).map((node) => String(node.noteId)));
    if (existingNodes.length && hasBackupFolder && (state.userNotes || []).every((note) => noteNodeIds.has(String(note.id)))) return;
    const subjectMap = new Map(); // subject -> nodeId
    let backupFolderId = existingNodes.find((node) => node?.type === "folder" && String(node.title || "").trim().toLowerCase() === "backup")?.id || null;
    if (!backupFolderId && (state.userNotes || []).length) {
        const backupFolder = await createUserNoteNodeSafe({
            type: "folder",
            title: "backup",
            parentId: null,
            metadata: { color: "#475569", level: "backup" }
        });
        backupFolderId = backupFolder?.id || null;
    }
    for (const note of (state.userNotes || [])) {
        if (noteNodeIds.has(String(note.id))) continue;
        const subject = String(note.subject || "General").trim() || "General";
        let subjectNodeId = subjectMap.get(subject);
        if (!subjectNodeId) {
            const existingSubject = existingNodes.find((node) => node?.type === "folder" && !node?.parentId && String(node.title || "").trim() === subject);
            if (existingSubject?.id) {
                subjectNodeId = existingSubject.id;
            } else {
                const created = await createUserNoteNodeSafe({
                    type: "folder",
                    title: subject,
                    parentId: backupFolderId || null,
                    metadata: { color: pickSubjectColor(subject), level: "subject" }
                });
                subjectNodeId = created.id;
            }
            subjectMap.set(subject, subjectNodeId);
        }
        await createUserNoteNodeSafe({
            type: "note",
            title: String(note.title || "Untitled").trim() || "Untitled",
            parentId: subjectNodeId,
            metadata: { color: pickSubjectColor(subject) },
            noteId: note.id
        });
    }
    try { localStorage.setItem(NOTES_TREE_SEED_DONE_KEY, "1"); } catch {}
}

function pickSubjectColor(subject) {
    const palette = ["#2563eb", "#16a34a", "#dc2626", "#7c3aed", "#d97706", "#0891b2", "#db2777", "#65a30d", "#4f46e5", "#0f766e"];
    const s = String(subject || "General");
    let h = 0;
    for (let i = 0; i < s.length; i++) h = (h * 31 + s.charCodeAt(i)) >>> 0;
    return palette[h % palette.length];
}

function slugToViewFromHash(slug) {
    const entry = Object.entries(VIEW_HASH_SLUGS).find(([, s]) => s === slug);
    return entry ? entry[0] : null;
}

function applyViewFromLocationHash() {
    const raw = (location.hash || "").replace(/^#\/?/, "").split(/[?#]/)[0];
    if (!raw || raw === "/") return;
    const v = slugToViewFromHash(raw);
    if (v) state.currentView = v;
}

function syncLocationHashFromView() {
    const slug = VIEW_HASH_SLUGS[state.currentView];
    if (slug === undefined) return;
    if (slug === "" && state.currentView === "dashboard") {
        if (location.hash) {
            history.replaceState(null, "", `${location.pathname}${location.search}`);
        }
        return;
    }
    const next = `#/${slug}`;
    if (location.hash !== next) {
        history.replaceState(null, "", `${location.pathname}${location.search}${next}`);
    }
}

function formattedAttemptTimestamp() {
    return new Date().toLocaleString([], {
        day: "2-digit",
        month: "short",
        year: "numeric",
        hour: "2-digit",
        minute: "2-digit"
    });
}
function resolveAttemptTitle(defaultParts = []) {
    const ts = formattedAttemptTimestamp();
    const stage = String(state.practiceExamStage || "Prelims").trim() || "Prelims";
    const base = defaultParts.filter(Boolean).join(" - ").trim();
    return `${base || "Practice Test"} • ${stage} - ${ts}`;
}

