// Helper function to get default test ID - prefers '2025-GS1 prelims' if available
function getDefaultTestId() {
    // Try to find the 2025-GS1 prelims test
    const preferredTest = sampleTests.find(t => 
        t.title?.includes("2025-GS1") || 
        t.title?.includes("2025 GS1") ||
        (t.title?.toLowerCase().includes("2025") && t.title?.toLowerCase().includes("gs1"))
    );
    return preferredTest?.id || sampleTests[0]?.id || null;
}

