// ================= INDEXEDDB QUESTION CACHE =================
const QUESTION_CACHE_DB_NAME = 'UPSCVaultCache';
const QUESTION_CACHE_DB_VERSION = 1;
const QUESTION_CACHE_STORE_NAME = 'questionCache';
const QUESTION_CACHE_METADATA_KEY = '__metadata__';
// Bump when cached question shape changes (e.g. we start persisting full vault metadata).
const QUESTION_CACHE_ENTRY_VERSION = 2;
let questionCacheDB = null;

// Initialize IndexedDB for question caching
async function initQuestionCacheDB() {
    if (questionCacheDB) return questionCacheDB;
    
    return new Promise((resolve, reject) => {
        const request = indexedDB.open(QUESTION_CACHE_DB_NAME, QUESTION_CACHE_DB_VERSION);
        
        request.onerror = () => reject(request.error);
        request.onsuccess = () => {
            questionCacheDB = request.result;
            resolve(questionCacheDB);
        };
        
        request.onupgradeneeded = (event) => {
            const db = event.target.result;
            if (!db.objectStoreNames.contains(QUESTION_CACHE_STORE_NAME)) {
                const store = db.createObjectStore(QUESTION_CACHE_STORE_NAME, { keyPath: 'testId' });
                store.createIndex('timestamp', 'timestamp', { unique: false });
                store.createIndex('subject', 'subject', { unique: false });
            }
        };
    });
}

// Save questions to IndexedDB cache
async function saveQuestionsToCache(testId, questions, testMetadata = {}) {
    try {
        const db = await initQuestionCacheDB();
        const transaction = db.transaction([QUESTION_CACHE_STORE_NAME], 'readwrite');
        const store = transaction.objectStore(QUESTION_CACHE_STORE_NAME);
        
        const cacheEntry = {
            testId,
            questions,
            metadata: testMetadata,
            timestamp: Date.now(),
            version: QUESTION_CACHE_ENTRY_VERSION
        };
        
        await new Promise((resolve, reject) => {
            const request = store.put(cacheEntry);
            request.onsuccess = () => resolve();
            request.onerror = () => reject(request.error);
        });
        
        console.log(`[IndexedDB] Cached ${questions.length} questions for test ${testId}`);
        return true;
    } catch (error) {
        console.warn('[IndexedDB] Failed to save questions to cache:', error);
        return false;
    }
}

// Load questions from IndexedDB cache
async function loadQuestionsFromCache(testId) {
    try {
        const db = await initQuestionCacheDB();
        const transaction = db.transaction([QUESTION_CACHE_STORE_NAME], 'readonly');
        const store = transaction.objectStore(QUESTION_CACHE_STORE_NAME);
        
        const cacheEntry = await new Promise((resolve, reject) => {
            const request = store.get(testId);
            request.onsuccess = () => resolve(request.result);
            request.onerror = () => reject(request.error);
        });
        
        if (cacheEntry && cacheEntry.questions) {
            if (cacheEntry.version !== QUESTION_CACHE_ENTRY_VERSION) {
                console.log(`[IndexedDB] Cache schema mismatch for ${testId}, will refresh`);
                return null;
            }
            // Check if cache is stale (older than 7 days)
            const cacheAge = Date.now() - cacheEntry.timestamp;
            const maxAge = 7 * 24 * 60 * 60 * 1000; // 7 days
            
            if (cacheAge > maxAge) {
                console.log(`[IndexedDB] Cache for ${testId} is stale, will refresh`);
                return null;
            }
            
            console.log(`[IndexedDB] Loaded ${cacheEntry.questions.length} questions from cache for ${testId}`);
            return cacheEntry.questions;
        }
        
        return null;
    } catch (error) {
        console.warn('[IndexedDB] Failed to load questions from cache:', error);
        return null;
    }
}

// Clear old cached questions
async function clearOldQuestionCache(maxAgeDays = 30) {
    try {
        const db = await initQuestionCacheDB();
        const transaction = db.transaction([QUESTION_CACHE_STORE_NAME], 'readwrite');
        const store = transaction.objectStore(QUESTION_CACHE_STORE_NAME);
        const index = store.index('timestamp');
        
        const cutoffTime = Date.now() - (maxAgeDays * 24 * 60 * 60 * 1000);
        const oldEntries = [];
        
        await new Promise((resolve, reject) => {
            const cursor = index.openCursor(IDBKeyRange.upperBound(cutoffTime));
            cursor.onsuccess = (event) => {
                const result = event.target.result;
                if (result) {
                    oldEntries.push(result.value.testId);
                    store.delete(result.value.testId);
                    result.continue();
                } else {
                    resolve();
                }
            };
            cursor.onerror = () => reject(cursor.error);
        });
        
        if (oldEntries.length > 0) {
            console.log(`[IndexedDB] Cleared ${oldEntries.length} old cache entries`);
        }
        
        return oldEntries.length;
    } catch (error) {
        console.warn('[IndexedDB] Failed to clear old cache:', error);
        return 0;
    }
}

async function removeQuestionsFromCache(testIds = []) {
    const uniqueIds = [...new Set((testIds || []).filter(Boolean))];
    if (!uniqueIds.length) return 0;
    try {
        const db = await initQuestionCacheDB();
        const transaction = db.transaction([QUESTION_CACHE_STORE_NAME], 'readwrite');
        const store = transaction.objectStore(QUESTION_CACHE_STORE_NAME);
        let removed = 0;
        await Promise.all(uniqueIds.map((testId) => new Promise((resolve) => {
            const request = store.delete(testId);
            request.onsuccess = () => {
                removed += 1;
                resolve();
            };
            request.onerror = () => resolve();
        })));
        if (removed > 0) {
            console.log(`[IndexedDB] Removed ${removed} stale cache entries`);
        }
        return removed;
    } catch (error) {
        console.warn('[IndexedDB] Failed to remove stale cache entries:', error);
        return 0;
    }
}

// Get cache statistics
async function getQuestionCacheStats() {
    try {
        const db = await initQuestionCacheDB();
        const transaction = db.transaction([QUESTION_CACHE_STORE_NAME], 'readonly');
        const store = transaction.objectStore(QUESTION_CACHE_STORE_NAME);
        
        const allEntries = await new Promise((resolve, reject) => {
            const request = store.getAll();
            request.onsuccess = () => resolve(request.result);
            request.onerror = () => reject(request.error);
        });
        
        const metadata = allEntries.find(e => e.testId === QUESTION_CACHE_METADATA_KEY);
        const cachedTests = allEntries.filter(e => e.testId !== QUESTION_CACHE_METADATA_KEY);
        
        return {
            totalTests: cachedTests.length,
            totalQuestions: cachedTests.reduce((sum, e) => sum + (e.questions?.length || 0), 0),
            oldestCache: cachedTests.length > 0 ? Math.min(...cachedTests.map(e => e.timestamp)) : null,
            newestCache: cachedTests.length > 0 ? Math.max(...cachedTests.map(e => e.timestamp)) : null
        };
    } catch (error) {
        console.warn('[IndexedDB] Failed to get cache stats:', error);
        return null;
    }
}

