async function openTagInStudy(tagName, scope = {}, options = {}) {
    // First refresh question states from server to get latest tags
    if (state.currentUser) {
        await refreshQuestionStatesFromServer();
    }
    await ensureQuestionsLoadedForTests(tagCandidateTestIds());
    const pool = questionsWithTag(tagName).filter((question) => {
        if (scope.subject && String(question.__tagSubject || "") !== String(scope.subject)) return false;
        if (scope.sectionGroup && String(question.__tagSectionGroup || "") !== String(scope.sectionGroup)) return false;
        if (scope.microTopic && String(question.microTopic || "") !== String(scope.microTopic)) return false;
        return true;
    });
    if (!pool.length) {
        setAuthNotice(`No questions with tag "${tagName}" yet.`, "warning");
        renderApp();
        return;
    }
    const titleParts = [tagName, scope.subject, scope.sectionGroup, scope.microTopic].filter(Boolean);
    const meta = {
        id: `study-tag-${Date.now()}`,
        mode: "tag",
        title: `Tag: ${titleParts.join(" • ")}`,
        subtitle: `${pool.length} tagged question(s)`
    };
    if (options.newTab) {
        const payload = createStudySessionPayload(pool, meta);
        if (!saveSharedStudySession(payload)) {
            setAuthNotice("Could not open the tag study tab.", "warning");
            renderApp();
            return;
        }
        window.open(`${window.location.pathname}?studyMode=1`, "_blank", "noopener");
        return;
    }
    beginStudySession(pool, meta);
    renderApp();
}

function tagCandidateTestIds() {
    const hydratedIds = [...hydratedQuestionStatesByTestId.keys()];
    return hydratedIds.length ? hydratedIds : accessibleTests().map((test) => test.id);
}


function testQuestionTotal(test) {
    if (!test) return 0;
    if (isTestQuestionsLoaded(test)) {
        return test.questions?.length || 0;
    }
    return Number(test.questionCount || 0);
}

function sumQuestionTotals(tests = []) {
    const scope = state.practiceSourceFilter; // 'all', 'pyq', 'nonPyq'
    const tiers = state.practiceSelectedSourceTiers; // ['upscCse', 'upscAllied', 'otherExams']
    
    return (tests || []).reduce((sum, test) => {
        const stats = test.__sourceStats;
        if (!stats) return sum + (scope === "all" ? (test.questions?.length || 0) : 0);
        
        if (scope === "all") return sum + stats.total;
        if (scope === "nonPyq") return sum + stats.nonPyq;
        
        // PYQ Only mode
        let pyqSum = 0;
        if (tiers.includes("upscCse")) pyqSum += stats.upscCse;
        if (tiers.includes("upscAllied")) pyqSum += stats.upscAllied;
        if (tiers.includes("otherExams")) pyqSum += stats.otherExams;
        return sum + pyqSum;
    }, 0);
}

function selectedPyqTierSummaryLabel() {
    const tiers = state.practiceSelectedSourceTiers || [];
    if (tiers.length === 0 || tiers.length === PYQ_SUB_FILTERS.length) return "All PYQs";
    if (tiers.length === 1) {
        if (tiers[0] === "upscCse") return "UPSC CSE";
        if (tiers[0] === "upscAllied") return "UPSC Allied Exams";
        if (tiers[0] === "otherExams") return "Other Exams";
    }
    return `${tiers.length} PYQ categories`;
}

function relevantTopicTests() {
    return memoizeDerivedView("relevantTopicTests", {
        user: isLoggedIn() ? "auth" : "guest",
        subject: state.practiceTopicSubject,
        sectionGroup: state.practiceTopicSectionGroup,
        providers: [...(state.syllabusProviderFilters || [])].sort(),
        programs: [...(state.syllabusProgramFilters || [])].sort(),
        series: [...(state.syllabusSeriesFilters || [])].sort()
    }, () => (
        accessibleTests().filter((test) => testMatchesProgramFilter(test, state.syllabusProgramFilters)).filter((test) => {
            if (state.practiceTopicSubject && state.practiceTopicSubject !== "All Subjects") {
                const hasSubject = (test.questions || []).some((q) => questionSubjectValue(q, test) === state.practiceTopicSubject);
                if (!hasSubject) return false;
            }
            if (state.practiceTopicSectionGroup && state.practiceTopicSectionGroup !== "All") {
                const hasSection = (test.questions || []).some((q) => questionSectionGroupValue(q, test) === state.practiceTopicSectionGroup);
                if (!hasSection) return false;
            }

            const matchesProvider = state.syllabusProviderFilters.length === 0
                || state.syllabusProviderFilters.includes("All Providers")
                || state.syllabusProviderFilters.includes(testInstituteValue(test));
            if (!matchesProvider) return false;

            const matchesSeries = state.syllabusSeriesFilters.length === 0
                || state.syllabusSeriesFilters.includes("All Collections")
                || state.syllabusSeriesFilters.includes(normalizeStageLabel(questionStageValue((test.questions || [])[0] || {}, test)))
                || state.syllabusSeriesFilters.includes(test.series);
            if (!matchesSeries) return false;

            return true;
        })
    ));
}

function canEstimateTopicPoolFromMetadata() {
    // We can use pre-calculated stats as long as we aren't filtering by deep micro-topics
    return !state.practiceMicroTopicFilters.length
        && (!state.practiceTopicMicroTopic || state.practiceTopicMicroTopic === "All");
}

function topicPoolCountSummary() {
    // If we have to calculate the full count, do it as efficiently as possible
    if (canEstimateTopicPoolFromMetadata() && state.practiceSourceFilter === "all") {
        const tests = relevantTopicTests();
        return {
            count: sumQuestionTotals(tests),
            exact: tests.every((test) => isTestQuestionsLoaded(test))
        };
    }
    
    const count = buildSyllabusPracticeQuestions().length;
    const tests = relevantTopicTests();
    const exact = tests.every((test) => isTestQuestionsLoaded(test));
    return { count, exact };
}

function selectedTagQuestions() {
    return questionsWithTag(state.selectedTagName);
}

function tagRelevantTestIds(selectedTags = []) {
    const tags = (selectedTags || []).filter(Boolean);
    if (!tags.length) return [];
    return memoizeDerivedView("tagRelevantTestIds", {
        user: isLoggedIn() ? "auth" : "guest",
        tags: [...tags].sort()
    }, () => {
        const ids = new Set();
        accessibleTests().forEach((test) => {
            const matchesLoaded = (test.questions || []).some((question) =>
                Array.isArray(question.reviewTags) && question.reviewTags.some((tag) => tags.includes(tag))
            );
            if (matchesLoaded) ids.add(test.id);
        });
        hydratedQuestionStatesByTestId.forEach((statesForTest, testId) => {
            if ((statesForTest || []).some((item) => Array.isArray(item.reviewTags) && item.reviewTags.some((tag) => tags.includes(tag)))) {
                ids.add(testId);
            }
        });
        return [...ids];
    });
}

