function noteReadingNoteIdFromHash() {
    const raw = String(window.location.hash || "").replace(/^#\/?/, "");
    const parts = raw.split("/");
    if (parts[0] !== "read") return "";
    return decodeURIComponent(parts.slice(1).join("/")).trim();
}

