function renderStandaloneReadMode() {
    const payload = loadReadModeSession();
    const session = payload?.studySession || state.studySession;
    const answers = payload?.studyAnswers || state.studyAnswers || {};
    // Ensure read-mode tab can reuse Study actions (tags/notes/source switcher) by hydrating state.
    if (payload?.studySession?.questions?.length) {
        state.studySession = payload.studySession;
        state.studyAnswers = payload.studyAnswers || {};
    }
    if (payload?.studySortPrimary === "year" || payload?.studySortPrimary === "number") {
        state.studySortPrimary = payload.studySortPrimary;
    }
    if (payload?.studyYearSort === "asc" || payload?.studyYearSort === "desc") {
        state.studyYearSort = payload.studyYearSort;
    }
    if (!session?.questions?.length) {
        return `
            <div class="reader-shell">
                <section class="reader-page">
                    <p class="eyebrow">Read Mode</p>
                    <h1 style="font-size: clamp(2.5rem, 6vw, 4.2rem); margin-bottom: 32px; line-height: 1.1; font-family: 'Playfair Display', serif; font-weight: 800; color: var(--accent-strong); width: 100%; text-align: center;">
                    <span style="display: block; white-space: nowrap;">Transform your Preparation.</span>
                    <span class="hero-accent typewriter-hero" style="display: block; margin-top: 12px; font-size: 0.7em; opacity: 0.9;">Master the UPSC Syllabus systematically.</span>
                </h1>
                    <p class="muted">No saved read session was found for this tab yet. Start any study flow with "Textbook-Themed Study Mode" or use "Open read mode" from an active study session to load the filtered questions here.</p>
                </section>
            </div>
        `;
    }
    const page = readModePage();
    const totalPages = Math.max(1, Math.ceil(session.questions.length / STUDY_PAGE_SIZE));
    const normalizedPage = Math.min(page, totalPages);
    const start = (normalizedPage - 1) * STUDY_PAGE_SIZE;
    const visibleQuestions = session.questions.slice(start, start + STUDY_PAGE_SIZE);
    const pageStart = visibleQuestions.length ? start + 1 : 0;
    const pageEnd = Math.min(start + STUDY_PAGE_SIZE, session.questions.length);
    const buildReadPageHref = (targetPage) => {
        const params = new URLSearchParams(window.location.search);
        params.set("readMode", "1");
        params.set("page", String(targetPage));
        return `${window.location.pathname}?${params.toString()}`;
    };
    return `
        <div class="reader-shell">
            <section class="reader-page">
                <div class="reader-head">
                    <div>
                        <p class="eyebrow">Focused Read Mode</p>
                        <h1>${session.title}</h1>
                        <p class="muted">${session.subtitle || "Book-like reading view"}</p>
                        <p class="muted">Showing ${pageStart}-${pageEnd} of ${session.questions.length} questions</p>
                    </div>
                    <div class="stacked-chips">
                        <span class="chip active-chip">Page ${normalizedPage} of ${totalPages}</span>
                        <button class="chip" type="button" id="readYearSortBtn" title="Cycle sort: Q# order → year (desc) → year (asc)">
                            ${state.studySortPrimary === "year" ? `Year ${state.studyYearSort === "asc" ? "↑" : "↓"}` : "Q# order"}
                        </button>
                        <button class="ghost-btn small" type="button" id="readerCloseBtn">Close</button>
                    </div>
                </div>
                <div class="study-pagination-bar">
                    <div class="study-pagination-meta">
                        <strong>Showing ${pageStart}-${pageEnd}</strong>
                        <span class="muted">20 questions per page</span>
                    </div>
                    <div class="study-pagination-controls">
                        <a class="ghost-btn small ${normalizedPage === 1 ? "disabled-link" : ""}" href="${normalizedPage === 1 ? "#" : buildReadPageHref(1)}">First</a>
                        <a class="ghost-btn small ${normalizedPage === 1 ? "disabled-link" : ""}" href="${normalizedPage === 1 ? "#" : buildReadPageHref(Math.max(1, normalizedPage - 1))}">Previous</a>
                        ${Array.from({ length: Math.min(totalPages, 5) }, (_, index) => {
                            const windowStart = Math.max(1, Math.min(normalizedPage - 2, totalPages - 4));
                            const candidate = windowStart + index;
                            if (candidate > totalPages) return "";
                            return `<a class="chip ${candidate === normalizedPage ? "active-chip" : ""}" href="${buildReadPageHref(candidate)}">${candidate}</a>`;
                        }).join("")}
                        <a class="ghost-btn small ${normalizedPage === totalPages ? "disabled-link" : ""}" href="${normalizedPage === totalPages ? "#" : buildReadPageHref(Math.min(totalPages, normalizedPage + 1))}">Next</a>
                        <a class="ghost-btn small ${normalizedPage === totalPages ? "disabled-link" : ""}" href="${normalizedPage === totalPages ? "#" : buildReadPageHref(totalPages)}">Last</a>
                    </div>
                </div>
                <div class="reader-stack">
                    ${visibleQuestions.map((question, index) => `
                        <article class="reader-question ${index % 2 === 0 ? "reader-left-page" : "reader-right-page"}">
                            <div class="review-head">
                                <span class="label">Q${question.questionNumber}</span>
                                ${renderQuestionCornerMeta(question)}
                            </div>
                            ${renderAnswerConflictWarning(question)}
                            <div class="question-text-block compact-question">${renderQuestionContent(question)}</div>
                            <div class="review-options">
                                ${orderedOptions(question.options).map(([key, value]) => {
                                    const selectedAnswer = state.studyAnswers[question.id] || answers[question.id] || "";
                                    const isCorrect = selectedAnswer && question.correctAnswer === key;
                                    const isSelected = selectedAnswer === key;
                                    const optionState = isCorrect && isSelected
                                        ? "review-option correct selected"
                                        : isCorrect
                                            ? "review-option correct"
                                            : isSelected
                                                ? "review-option incorrect selected"
                                                : "review-option";
                                    const optionLabel = selectedAnswer
                                        ? (isCorrect && isSelected
                                            ? '<span class="review-badge success">Your correct answer</span>'
                                            : isCorrect
                                                ? '<span class="review-badge success">Correct answer</span>'
                                                : isSelected
                                                    ? '<span class="review-badge danger">Your answer</span>'
                                                    : "")
                                        : "";
                                    return `<button class="${optionState}" type="button" data-read-answer="${question.id}" data-read-choice="${key}"><div class="review-option-main"><strong>${key})</strong><span>${value}</span></div>${optionLabel}</button>`;
                                }).join("")}
                            </div>
                            <div class="study-card-actions">
                                <button class="ghost-btn small" type="button" data-read-toggle-explanation="${question.id}">${state.studyExplanationOpen.includes(question.id) ? "Hide explanation" : "Show explanation"}</button>
                            </div>
                            <div class="review-tag-cluster">
                                <div class="stacked-chips compact-review-tags">${(question.reviewTags || []).map((tag) => `<span class="chip active-chip">${tag}</span>`).join("") || `<span class="muted">No learning tags yet</span>`}</div>
                            </div>
                            <div class="study-tag-chip-block">
                                <span class="label">Assign learning tag</span>
                                <div class="stacked-chips compact-review-tags">
                                    ${allLearningTags().map((tag) => `<button class="chip ${question.reviewTags?.includes(tag) ? "active-chip" : ""}" type="button" data-study-tag-choice="${question.id}" data-study-tag-value="${tag}">${tag}</button>`).join("")}
                                    <button class="chip" type="button" data-study-create-tag="${question.id}" title="Create new tag">+</button>
                                </div>
                                <input type="text" class="new-tag-input" data-study-new-tag="${question.id}" placeholder="Enter new tag..." style="display: none; width: 100%; margin-top: 4px; padding: 6px; border: 1px solid var(--line); border-radius: 8px;">
                            </div>
                            ${state.studyExplanationOpen.includes(question.id) ? `<div class="details-block">
                                ${renderExplanationSourceSwitcher(explanationRenderQuestion(question))}
                                <p><strong>Correct answer</strong></p>
                                <p class="muted">${(question.correctAnswer || "").toUpperCase()}${question.options?.[question.correctAnswer] ? ` • ${question.options[question.correctAnswer]}` : ""}</p>
                                <p><strong>Explanation</strong></p>
                                <div>${renderSimpleMarkdown(getExplanationMarkdown(explanationRenderQuestion(question)) || "No explanation available.")}</div>
                                <div class="stacked-chips" style="margin-top: 10px;">
                                    <button class="ghost-btn small" type="button" data-add-to-notebook="${question.id}">Add to Notebook</button>
                                    <button class="ghost-btn small" type="button" data-quick-save-notebook="${question.id}" title="Save to last-used notebook + section">Quick Save</button>
                                </div>
                                ${renderAlsoAppearsIn(question)}
                            </div>` : ""}
                            <div class="note-layer">
                                <span class="label">Personal note</span>
                                <textarea rows="2" data-study-note="${question.id}" placeholder="Short memory aid or reminder">${escapeHtml(Object.prototype.hasOwnProperty.call(state.studyNoteDrafts, question.id) ? state.studyNoteDrafts[question.id] : (question.note || ""))}</textarea>
                                <button class="ghost-btn small" type="button" data-save-note="${question.id}" style="margin-top: 8px;">Save Note</button>
                            </div>
                        </article>
                    `).join("")}
                </div>
            </section>
        </div>
    `;
}

function handleReadModeAnswer(questionId, choice) {
    if (!questionId || !choice) return;
    state.studyAnswers = {
        ...state.studyAnswers,
        [questionId]: choice
    };
    renderApp();
}

function toggleReadModeExplanation(questionId) {
    if (!questionId) return;
    state.studyExplanationOpen = state.studyExplanationOpen.includes(questionId)
        ? state.studyExplanationOpen.filter((item) => item !== questionId)
        : [...state.studyExplanationOpen, questionId];
    renderApp();
}

function openQuestionNotebookSave(questionId) {
    if (!isLoggedIn()) {
        setAuthNotice("Please log in to save highlights to Notes.", "warning");
        renderApp();
        return;
    }
    const selectionText = captureSelectedText();
    const text = selectionText || state.selectedText || "";
    if (!text || text.trim().length < 5) {
        setAuthNotice("Highlight some explanation text first, then click “Add to Notebook”.", "warning");
        renderApp();
        return;
    }
    const sessionQuestion = currentStudyQuestions().find((question) => question.id === questionId);
    const testId = sessionQuestion?.__studyTestId || sessionQuestion?.testId || state.selectedTestId || state.activeTestId || null;
    openSaveToNotePanel(text.trim(), {
        type: "question",
        questionId,
        testId
    });
}

async function quickSaveQuestionNotebook(questionId) {
    if (!isLoggedIn()) {
        setAuthNotice("Please log in to save highlights to Notes.", "warning");
        renderApp();
        return;
    }
    const prefs = loadNotesHighlightSavePrefs();
    if (!prefs?.noteId) {
        setAuthNotice("No last-used notebook yet. Use Add to Notebook once first.", "warning");
        renderApp();
        return;
    }
    const selectionText = captureSelectedText();
    const text = selectionText || state.selectedText || "";
    if (!text || text.trim().length < 5) {
        setAuthNotice("Highlight some explanation text first, then tap Quick Save.", "warning");
        renderApp();
        return;
    }
    const sessionQuestion = currentStudyQuestions().find((question) => question.id === questionId);
    const testId = sessionQuestion?.__studyTestId || sessionQuestion?.testId || state.selectedTestId || state.activeTestId || null;
    state.selectedText = text.trim();
    state.textSelectionSource = { type: "question", questionId, testId };
    await commitSaveHighlightToNote(prefs.noteId, prefs.headingKey || "__auto__");
}

async function saveStudyQuestionNote(questionId) {
    if (!questionId) return;
    const sessionQuestion = currentStudyQuestions().find((question) => question.id === questionId);
    if (!sessionQuestion) return;
    const draftNote = state.studyNoteDrafts[questionId] ?? sessionQuestion.note ?? "";
    try {
        await updateStudyQuestionState(questionId, {
            note: draftNote,
            savedFolders: sessionQuestion.savedFolders || []
        });
        setAuthNotice("Note saved successfully.", "success");
    } catch (error) {
        console.error("Failed to save note:", error);
        setAuthNotice("Failed to save note. Please try again.", "error");
    }
}

async function loadAllQuestionCacheEntries() {
    try {
        const db = await initQuestionCacheDB();
        const transaction = db.transaction([QUESTION_CACHE_STORE_NAME], "readonly");
        const store = transaction.objectStore(QUESTION_CACHE_STORE_NAME);
        const allEntries = await new Promise((resolve, reject) => {
            const request = store.getAll();
            request.onsuccess = () => resolve(request.result || []);
            request.onerror = () => reject(request.error);
        });
        return Array.isArray(allEntries) ? allEntries : [];
    } catch (error) {
        console.warn("[IndexedDB] Failed to load all question cache entries:", error);
        return [];
    }
}

async function hydrateLoadedQuestionsFromIndexedDb() {
    if (!sampleTests.length) return 0;
    const allEntries = await loadAllQuestionCacheEntries();
    if (!allEntries.length) return 0;

    const freshEntries = allEntries.filter((entry) => {
        if (!entry || !entry.testId || entry.testId === QUESTION_CACHE_METADATA_KEY) return false;
        if (entry.version !== QUESTION_CACHE_ENTRY_VERSION) return false;
        const cacheAge = Date.now() - Number(entry.timestamp || 0);
        return cacheAge <= 7 * 24 * 60 * 60 * 1000 && Array.isArray(entry.questions) && entry.questions.length > 0;
    });
    if (!freshEntries.length) return 0;

    let restoredTests = 0;
    for (const entry of freshEntries) {
        const current = sampleTests.find((item) => item.id === entry.testId);
        if (!current) continue;
        const expectedCount = Number(current.questionCount || 0);
        if (expectedCount > 0 && entry.questions.length < expectedCount) continue;
        const nextTest = normalizeImportedTest({
            ...current,
            questions: entry.questions,
            questionCount: current.questionCount || entry.questions.length,
            questionsLoaded: true
        });
        const cachedStates = hydratedQuestionStatesByTestId.get(entry.testId) || [];
        upsertTestInLibrary(cachedStates.length ? mergeQuestionState(nextTest, cachedStates) : nextTest);
        indexQuestionsForSearch(entry.questions, entry.testId);
        restoredTests += 1;
    }

    if (restoredTests > 0) {
        invalidatePracticeSearchCache();
        console.log(`[IndexedDB] Restored ${restoredTests} cached tests into memory on startup`);
    }
    return restoredTests;
}

function bindStandaloneReadModeActions() {
    document.querySelectorAll("[data-read-answer]").forEach((button) => button.addEventListener("click", () => {
        handleReadModeAnswer(button.dataset.readAnswer || "", button.dataset.readChoice || "");
    }));
    document.querySelectorAll("[data-read-toggle-explanation]").forEach((button) => button.addEventListener("click", () => {
        toggleReadModeExplanation(button.dataset.readToggleExplanation || "");
    }));
    document.querySelectorAll("[data-study-note]").forEach((box) => box.addEventListener("input", (event) => {
        state.studyNoteDrafts = {
            ...state.studyNoteDrafts,
            [event.target.dataset.studyNote]: event.target.value
        };
    }));
    document.querySelectorAll("[data-add-to-notebook]").forEach((button) => button.addEventListener("click", () => {
        openQuestionNotebookSave(button.dataset.addToNotebook || "");
    }));
    document.querySelectorAll("[data-quick-save-notebook]").forEach((button) => button.addEventListener("click", async () => {
        await quickSaveQuestionNotebook(button.dataset.quickSaveNotebook || "");
    }));
    document.querySelectorAll("[data-save-note]").forEach((button) => button.addEventListener("click", async (event) => {
        await saveStudyQuestionNote(event.target.dataset.saveNote);
    }));
}

