function renderSaveHighlightSectionStep() {
    const id = state.saveHighlightPendingNoteId;
    if (!id) return "";
    const pn = state.userNotes.find((n) => n.id === id);
    if (!pn) return "";
    const options = [
        { value: "__top__", label: "Top of note (before all sections)" },
        { value: "__auto__", label: "Auto: use question topic as section" }
    ];
    (pn.items || []).forEach((item) => {
        if (item?.type === "microTopicHeading") {
            const v = String(item.key || item.text || "").trim().toLowerCase();
            const lab = String(item.text || "").trim() || "Section";
            if (v && !options.some((o) => o.value === v)) {
                options.push({ value: v, label: lab });
            }
        }
    });
    return `
        <div class="save-highlight-section-step" style="margin-top: 16px; padding: 14px; border: 1px solid var(--line); border-radius: 10px; background: var(--surface-strong);">
            <p class="eyebrow" style="margin-bottom: 8px;">Place highlight in notebook: <strong>${escapeHtml(pn.title)}</strong></p>
            <p class="muted" style="font-size: 0.82rem; margin: 0 0 10px;">This is the <strong>subheading inside the note</strong> (section band in PDF), not the notebook file title.</p>
            <label class="small-label">Use existing section</label>
            <select id="saveHighlightHeadingSelectStep" class="notes-select" style="margin-top: 6px;">
                ${options.map((o) => `<option value="${escapeHtml(o.value)}">${escapeHtml(o.label)}</option>`).join("")}
            </select>
            <label class="small-label" style="margin-top: 14px; display:block;">Or type a new subheading (optional)</label>
            <p class="muted" style="font-size: 0.78rem; margin: 4px 0 8px;">If you fill this, it overrides the dropdown and creates that section in the note/PDF.</p>
            <input type="text" id="saveHighlightNewSectionTitleStep" placeholder="e.g., Fundamental Rights — Articles 12–35" style="width: 100%; padding: 8px 10px; border: 1px solid var(--line); border-radius: 8px; background: var(--surface);">
            <div class="stacked-chips" style="margin-top: 12px;">
                <button class="primary-btn small" type="button" id="confirmSaveHighlightWithSectionBtn">Save highlight here</button>
                <button class="ghost-btn small" type="button" id="cancelSaveHighlightNotePickBtn">Choose another note</button>
            </div>
        </div>
    `;
}

function renderSaveToNotePanel() {
    if (!state.saveToNotePanelOpen || !isLoggedIn()) return "";
    
    const folderNodes = notesFolderNodes();
    const selectedFolderId = String(state.saveHighlightFolderId || "").trim();
    const notebookNodes = selectedFolderId ? noteNodesInFolder(selectedFolderId) : [];
    const notebooksInFolder = notebookNodes
        .map((node) => state.userNotes.find((n) => String(n.id) === String(node.noteId)))
        .filter(Boolean);
    const selectedNoteId = state.saveHighlightPendingNoteId;
    const selectedNote = notebooksInFolder.find((n) => String(n.id) === String(selectedNoteId)) || null;
    const hierarchyTree = folderNodes.map((folder) => {
        const childNotes = noteNodesInFolder(String(folder.id))
            .map((node) => state.userNotes.find((n) => String(n.id) === String(node.noteId)))
            .filter(Boolean);
        return `
            <div class="save-hierarchy-folder">
                <button type="button" class="ghost-btn tiny ${selectedFolderId === String(folder.id) ? "active" : ""}" data-save-note-pick-folder="${escapeHtml(String(folder.id))}">📁 ${escapeHtml(folder.title)}</button>
                <div class="save-hierarchy-notes">
                    ${childNotes.length ? childNotes.map((note) => `
                        <button type="button" class="ghost-btn tiny ${String(selectedNoteId) === String(note.id) ? "active" : ""}" data-save-note-pick-note="${escapeHtml(String(note.id))}">
                            └ 📓 ${escapeHtml(note.title)}
                        </button>
                    `).join("") : `<span class="muted" style="font-size:0.78rem;">No notebooks</span>`}
                </div>
            </div>
        `;
    }).join("");

    const previewText = String(state.selectedText || "");
    
    const sourceInfo = state.textSelectionSource || {};
    let currentMicrotopic = "";
    if (sourceInfo.questionId) {
        const tests = (typeof sampleTests !== "undefined" && Array.isArray(sampleTests) && sampleTests.length)
            ? sampleTests
            : (window.sampleTests || []);
        let q = null;
        for (let t of tests) {
             const found = (t.questions || []).find(qn => String(qn.id) === String(sourceInfo.questionId));
             if (found) { q = found; break; }
        }
        if (!q && typeof currentStudyQuestions === "function") {
             q = currentStudyQuestions().find(qn => String(qn.id) === String(sourceInfo.questionId));
        }
        if (q) currentMicrotopic = q.microTopic || "";
    }

    const sectionOptions = [
        { value: "__auto__", label: "Auto (use question topic as section)" }
    ];
    if (currentMicrotopic) {
        sectionOptions.push({ value: currentMicrotopic, label: `Use current microtopic (${currentMicrotopic})`});
    }
    sectionOptions.push({ value: "__top__", label: "Top of notebook (no subheading)" });

    if (selectedNote) {
        (selectedNote.items || []).forEach((item) => {
            if (item?.type === "microTopicHeading") {
                const v = String(item.key || item.text || "").trim();
                const lab = String(item.text || "").trim() || "Section";
                if (v && !sectionOptions.some((o) => o.value === v)) {
                    sectionOptions.push({ value: v, label: lab });
                }
            }
        });
    }

    const defaultHeading = String(state.saveHighlightPrefHeadingKey || "__auto__");
    const prefs = loadNotesHighlightSavePrefs();
    const quickNote = prefs?.noteId && prefs?.subject
        ? state.userNotes.find((n) => String(n.id) === String(prefs.noteId) && n.subject === prefs.subject)
        : null;

    return `
        <div class="modal-backdrop save-note-backdrop" id="saveNoteBackdrop">
            <section class="confirm-modal save-note-modal" role="dialog" aria-modal="true" aria-labelledby="saveNoteTitle">
                <div class="section-head compact-section-head">
                    <div>
                        <p class="eyebrow">Save Highlight</p>
                        <h3 id="saveNoteTitle">Add to Notebook</h3>
                        <p class="muted">Review your selected text and choose where to save it.</p>
                    </div>
                    <button class="ghost-btn small" type="button" id="closeSaveNoteBtn" aria-label="Close">✕</button>
                </div>
                <div class="save-note-content" style="padding-top: 0;">
                    ${quickNote ? `
                    <div style="margin-bottom:16px;padding:12px;border:1px solid var(--line);border-radius:10px;background:var(--surface-strong);display:flex;justify-content:space-between;align-items:center;gap:12px;flex-wrap:wrap;">
                        <div class="muted" style="font-size:0.88rem;line-height:1.45;"><strong>Quick save:</strong> last notebook <strong>${escapeHtml(quickNote.title)}</strong> (${escapeHtml(quickNote.subject)})</div>
                        <button type="button" class="primary-btn small" id="quickSaveHighlightBtn">Save here</button>
                    </div>` : ""}
                    <div class="highlight-preview" style="margin-bottom: 20px;">
                        <label class="small-label" style="display:block; margin-bottom: 8px;">Selected Text → Bullet Points (Editable)</label>
                        <div class="save-note-bullets" id="saveNoteBullets">
                            ${(Array.isArray(state.saveNoteBulletDrafts) ? state.saveNoteBulletDrafts : splitTextIntoBulletDrafts(previewText)).map((t, idx) => `
                                <div class="save-note-bullet-row" data-save-note-bullet-row="${idx}">
                                    <div class="save-note-bullet-glyph">•</div>
                                    <textarea class="save-note-bullet-input" data-save-note-bullet="${idx}" rows="${Math.min(12, Math.max(4, 2 + Math.ceil(String(t || "").length / 90)))}" style="min-height:110px;" placeholder="Type a bullet point...">${escapeHtml(String(t || ""))}</textarea>
                                    <div class="save-note-bullet-actions">
                                        <button class="ghost-btn tiny" type="button" data-save-note-bullet-split="${idx}" title="Split into bullet at cursor">Split</button>
                                        <button class="ghost-btn tiny" type="button" data-save-note-bullet-add-after="${idx}" title="Add bullet below">+</button>
                                        <button class="ghost-btn tiny danger-btn" type="button" data-save-note-bullet-remove="${idx}" title="Remove bullet" ${idx === 0 && (state.saveNoteBulletDrafts?.length || 1) <= 1 ? "disabled" : ""}>✕</button>
                                    </div>
                                </div>
                            `).join("")}
                            <div class="save-note-bullet-footer">
                                
                            </div>
                        </div>
                    </div>

                    <div class="note-selection" style="display: flex; flex-direction: column; gap: 16px;">
                        <div>
                            <label class="small-label" style="display:flex; justify-content:space-between; margin-bottom: 6px;">
                                <span>1. Select Folder</span>
                            </label>
                            <div style="max-height:140px; overflow:auto; border:1px solid var(--line); border-radius:8px; padding:8px; margin-bottom:8px; background:var(--surface-strong);">
                                ${hierarchyTree || `<span class="muted" style="font-size:0.82rem;">No folders yet. Create one below.</span>`}
                            </div>
                            <select id="saveNoteFolderSelect" class="notes-select save-popup-compact-select" style="width:100%;">
                                <option value="">Choose a folder...</option>
                                ${folderNodes.map((folder) => `
                                    <option value="${String(folder.id)}" ${selectedFolderId === String(folder.id) ? "selected" : ""}>${escapeHtml(folder.title)}</option>
                                `).join("")}
                            </select>
                            <div style="margin-top: 8px; display:flex; gap:8px; align-items:center; flex-wrap:wrap;">
                               <input type="text" id="saveNoteNewFolderTitle" placeholder="New folder name" style="flex:1; min-width:200px; padding: 8px 10px; border: 1px solid var(--line); border-radius: 8px; font-size: 0.9rem;">
                               <button class="primary-btn small" type="button" id="saveNoteCreateFolderBtn">Create folder</button>
                            </div>
                        </div>

                        ${selectedFolderId ? `
                            <div>
                                <label class="small-label" style="margin-bottom: 6px; display:block;">2. Select Notebook</label>
                                <select id="saveNoteNotebookSelect" class="notes-select save-popup-compact-select" style="width:100%;">
                                    <option value="">Choose a notebook...</option>
                                    ${notebooksInFolder.map((n) => `
                                        <option value="${String(n.id)}" ${String(selectedNoteId) === String(n.id) ? "selected" : ""}>${escapeHtml(n.title)}</option>
                                    `).join("")}
                                </select>
                                <div style="margin-top: 8px;">
                                   <input type="text" id="saveNoteNewTitle" placeholder="Or type a title to create a new notebook" style="width: 100%; padding: 8px 10px; border: 1px solid var(--line); border-radius: 8px; font-size: 0.9rem;">
                                </div>
                            </div>
                        ` : ''}

                        ${selectedNoteId ? `
                            <div>
                                <label class="small-label" style="margin-bottom: 6px; display:block;">3. Select Section (Heading)</label>
                                <select id="saveHighlightHeadingSelect" class="notes-select save-popup-compact-select" style="width:100%; padding: 8px 10px; border-radius: 8px; border: 1px solid var(--line);">
                                    ${sectionOptions.map((o) => `<option value="${escapeHtml(o.value)}" ${String(o.value) === defaultHeading ? "selected" : ""}>${escapeHtml(o.label)}</option>`).join("")}
                                </select>
                                <div style="margin-top: 8px;">
                                    <input type="text" id="saveHighlightNewSectionTitle" placeholder="Or type to create a new section heading" style="width: 100%; padding: 9px 10px; border: 1px solid var(--line); border-radius: 8px; font-size: 0.9rem;">
                                </div>
                            </div>
                            
                            <div class="stacked-chips" style="margin-top: 24px; display: flex; justify-content: flex-end;">
                                <button class="primary-btn" type="button" id="confirmSaveHighlightCombinedBtn">Add Note</button>
                            </div>
                        ` : (selectedFolderId ? `
                            <div class="stacked-chips" style="margin-top: 16px;">
                                <button class="primary-btn small" type="button" id="createNoteAndSaveHighlightBtn">Create Notebook & Add Note</button>
                            </div>
                        ` : "")}
                    </div>
                </div>
            </section>
        </div>
    `;
}

function renderAccessGate(title, body, featureLabel = "Member Access") {
    const demoTests = demoAccessibleTests();
    const demoLabel = demoTests.length === 1
        ? `${demoTests[0]?.title || "The demo paper"} stays open as your sample paper.`
        : `${demoTests.length} demo papers stay open as your free sample library.`;
    return `
        <section class="panel lock-panel">
            <div class="section-head">
                <div>
                    <p class="eyebrow">${featureLabel}</p>
                    <h3>${title}</h3>
                    <p class="muted">${body}</p>
                </div>
            </div>
            <div class="lock-grid">
                <article class="panel lock-copy">
                    <p class="eyebrow">Demo Mode</p>
                    <h4>${demoLabel}</h4>
                    <p class="muted">Sign in to unlock saved reports, deeper analytics, future test library access, and synced revision data across devices.</p>
                </article>
                <article class="panel lock-auth">
                    ${renderAuthCard()}
                </article>
            </div>
        </section>
    `;
}

