// Render flashcard insights panel
function renderFlashcardInsights() {
    const cards = getCachedUserCards();
    if (!cards || cards.length === 0) return "";
    
    const totalCards = cards.length;
    const frozenCards = cards.filter(c => c.frozen).length;
    const newCards = cards.filter(c => c.state === 'new').length;
    const learningCards = cards.filter(c => c.state === 'learning').length;
    const reviewCards = cards.filter(c => c.state === 'review').length;
    
    const avgEaseFactor = cards.reduce((sum, c) => sum + (c.easeFactor || 2.5), 0) / totalCards;
    const totalReviews = cards.reduce((sum, c) => sum + (c.reviewCount || 0), 0);
    
    return `
        <div style="margin-bottom: 24px; padding: 16px; background: var(--surface); border-radius: 12px; border: 1px solid var(--line);">
            <h4 style="margin: 0 0 12px 0; font-size: 0.9rem;">Flashcard Insights</h4>
            <div style="display: grid; grid-template-columns: repeat(auto-fit, minmax(120px, 1fr)); gap: 12px;">
                <div style="text-align: center; padding: 12px; background: var(--surface-strong); border-radius: 8px;">
                    <div style="font-size: 1.5rem; font-weight: 700; color: var(--accent);">${frozenCards}</div>
                    <div style="font-size: 0.75rem; color: var(--muted);">Frozen</div>
                </div>
                <div style="text-align: center; padding: 12px; background: var(--surface-strong); border-radius: 8px;">
                    <div style="font-size: 1.5rem; font-weight: 700; color: #3b82f6;">${newCards}</div>
                    <div style="font-size: 0.75rem; color: var(--muted);">New</div>
                </div>
                <div style="text-align: center; padding: 12px; background: var(--surface-strong); border-radius: 8px;">
                    <div style="font-size: 1.5rem; font-weight: 700; color: #f59e0b;">${learningCards}</div>
                    <div style="font-size: 0.75rem; color: var(--muted);">Learning</div>
                </div>
                <div style="text-align: center; padding: 12px; background: var(--surface-strong); border-radius: 8px;">
                    <div style="font-size: 1.5rem; font-weight: 700; color: #10b981;">${reviewCards}</div>
                    <div style="font-size: 0.75rem; color: var(--muted);">Review</div>
                </div>
                <div style="text-align: center; padding: 12px; background: var(--surface-strong); border-radius: 8px;">
                    <div style="font-size: 1.5rem; font-weight: 700; color: #8b5cf6;">${avgEaseFactor.toFixed(2)}</div>
                    <div style="font-size: 0.75rem; color: var(--muted);">Avg Ease</div>
                </div>
                <div style="text-align: center; padding: 12px; background: var(--surface-strong); border-radius: 8px;">
                    <div style="font-size: 1.5rem; font-weight: 700; color: #ec4899;">${totalReviews}</div>
                    <div style="font-size: 0.75rem; color: var(--muted);">Total Reviews</div>
                </div>
            </div>
        </div>
    `;
}

