// ================= PDF VIEWER FUNCTION =================

function renderPdfViewer() {
    if (!isLoggedIn()) {
        return renderAccessGate("PDF Viewer unlocks after sign in", "Upload and highlight PDFs for your UPSC preparation.", "PDF Viewer");
    }
    
    // Get current folder contents
    const currentFolderItems = state.pdfLibrary.filter(item => item.parentId === state.pdfCurrentFolderId);
    const folders = currentFolderItems.filter(item => item.type === 'folder');
    const pdfs = currentFolderItems.filter(item => item.type === 'pdf');
    
    // Build breadcrumb
    const breadcrumb = [];
    let currentId = state.pdfCurrentFolderId;
    while (currentId) {
        const item = state.pdfLibrary.find(i => i.id === currentId);
        if (item) {
            breadcrumb.unshift({ id: item.id, name: item.name });
            currentId = item.parentId;
        } else {
            break;
        }
    }
    
    return `
        <section class="panel">
            ${!state.pdfOpenPdfId ? `
                <!-- Directory View -->
                <div class="section-head compact-section-head">
                    <div>
                        <p class="eyebrow">📁 PDF Library</p>
                        <h3>Your PDF Documents</h3>
                        <p class="muted">Organize and highlight your PDFs for study notes.</p>
                    </div>
                    <div style="display: flex; gap: 12px;">
                        <button id="createFolderBtn" class="secondary-btn" style="padding: 10px 16px;">
                            <i class="fas fa-folder-plus"></i> New Folder
                        </button>
                        <button id="uploadPdfBtn" class="primary-btn" style="padding: 10px 16px;">
                            <i class="fas fa-upload"></i> Upload PDF
                        </button>
                        <input type="file" id="pdfUploadInput" accept=".pdf" style="display: none;">
                    </div>
                </div>
                
                <!-- Breadcrumb -->
                <div style="display: flex; align-items: center; gap: 8px; padding: 12px 16px; background: var(--surface-weak); border-radius: 8px; margin-bottom: 20px;">
                    <button id="goToRootBtn" style="background: none; border: none; color: var(--accent); cursor: pointer; padding: 4px 8px;">
                        <i class="fas fa-home"></i>
                    </button>
                    ${breadcrumb.map((crumb, index) => `
                        <span style="color: var(--muted);">/</span>
                        <button class="breadcrumb-btn" data-id="${crumb.id}" style="background: none; border: none; color: ${index === breadcrumb.length - 1 ? 'var(--text)' : 'var(--accent)'}; cursor: pointer; padding: 4px 8px;">
                            ${escapeHtml(crumb.name)}
                        </button>
                    `).join('')}
                </div>
                
                <!-- Directory Grid -->
                ${folders.length === 0 && pdfs.length === 0 ? `
                    <div style="display: flex; flex-direction: column; align-items: center; justify-content: center; padding: 80px 20px; border: 2px dashed var(--line); border-radius: 12px; background: var(--surface-weak);">
                        <div style="font-size: 4rem; margin-bottom: 16px;">📁</div>
                        <h3 style="margin: 0 0 8px 0;">Empty Folder</h3>
                        <p class="muted" style="margin-bottom: 24px;">Create folders or upload PDFs to get started</p>
                    </div>
                ` : `
                    <div style="display: grid; grid-template-columns: repeat(auto-fill, minmax(200px, 1fr)); gap: 16px;">
                        ${folders.map(folder => `
                            <div class="folder-item" data-id="${folder.id}" style="padding: 20px; background: var(--surface-strong); border-radius: 12px; cursor: pointer; transition: all 0.2s; border: 1px solid var(--line);">
                                <div style="font-size: 2.5rem; margin-bottom: 12px;">📁</div>
                                <h4 style="margin: 0; font-size: 1rem; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;">${escapeHtml(folder.name)}</h4>
                                <p class="muted" style="margin: 4px 0 0 0; font-size: 0.8rem;">${folder.children?.length || 0} items</p>
                            </div>
                        `).join('')}
                        ${pdfs.map(pdf => `
                            <div class="pdf-item" data-id="${pdf.id}" style="padding: 20px; background: var(--surface-strong); border-radius: 12px; cursor: pointer; transition: all 0.2s; border: 1px solid var(--line);">
                                <div style="font-size: 2.5rem; margin-bottom: 12px;">📄</div>
                                <h4 style="margin: 0; font-size: 1rem; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;">${escapeHtml(pdf.name)}</h4>
                                <p class="muted" style="margin: 4px 0 0 0; font-size: 0.8rem;">${pdf.highlights?.length || 0} highlights</p>
                            </div>
                        `).join('')}
                    </div>
                `}
            ` : `
                <!-- PDF Viewer -->
                <div class="section-head compact-section-head">
                    <div>
                        <button id="backToLibraryBtn" style="display: flex; align-items: center; gap: 8px; padding: 8px 16px; background: var(--surface-strong); border: 1px solid var(--line); border-radius: 8px; cursor: pointer; margin-bottom: 12px;">
                            <i class="fas fa-arrow-left"></i> Back to Library
                        </button>
                        <p class="eyebrow">📄 PDF Viewer</p>
                        <h3>${escapeHtml(state.pdfOpenPdfName)}</h3>
                        <p class="muted">Highlight important points. Orange = Subtopic, Green = Bullet Point</p>
                    </div>
                    <div style="display: flex; gap: 12px; align-items: center;">
                        <!-- Color Picker -->
                        <div style="display: flex; gap: 8px;">
                            <button class="highlight-color-btn ${state.pdfCurrentHighlightColor === '#FFA500' ? 'active' : ''}" data-color="#FFA500" data-type="subtopic" style="width: 36px; height: 36px; border-radius: 50%; background: #FFA500; border: 3px solid ${state.pdfCurrentHighlightColor === '#FFA500' ? 'var(--accent)' : 'transparent'}; cursor: pointer;" title="Orange = Subtopic"></button>
                            <button class="highlight-color-btn ${state.pdfCurrentHighlightColor === '#22C55E' ? 'active' : ''}" data-color="#22C55E" data-type="bullet" style="width: 36px; height: 36px; border-radius: 50%; background: #22C55E; border: 3px solid ${state.pdfCurrentHighlightColor === '#22C55E' ? 'var(--accent)' : 'transparent'}; cursor: pointer;" title="Green = Bullet Point"></button>
                            <button class="highlight-color-btn ${state.pdfCurrentHighlightColor === '#3B82F6' ? 'active' : ''}" data-color="#3B82F6" data-type="note" style="width: 36px; height: 36px; border-radius: 50%; background: #3B82F6; border: 3px solid ${state.pdfCurrentHighlightColor === '#3B82F6' ? 'var(--accent)' : 'transparent'}; cursor: pointer;" title="Blue = Note"></button>
                            <button class="highlight-color-btn ${state.pdfCurrentHighlightColor === '#EF4444' ? 'active' : ''}" data-color="#EF4444" data-type="important" style="width: 36px; height: 36px; border-radius: 50%; background: #EF4444; border: 3px solid ${state.pdfCurrentHighlightColor === '#EF4444' ? 'var(--accent)' : 'transparent'}; cursor: pointer;" title="Red = Important"></button>
                        </div>
                        <button id="downloadNotesBtn" class="secondary-btn" style="padding: 10px 16px;">
                            <i class="fas fa-download"></i> Download Notes
                        </button>
                    </div>
                </div>
                
                <div style="display: flex; gap: 20px; height: calc(100vh - 250px);">
                    <!-- PDF Canvas -->
                    <div style="flex: 1; display: flex; flex-direction: column; background: var(--surface-weak); border-radius: 12px; overflow: hidden;">
                        <div style="display: flex; align-items: center; justify-content: space-between; padding: 12px 16px; background: var(--surface-strong); border-bottom: 1px solid var(--line);">
                            <div style="display: flex; align-items: center; gap: 12px;">
                                <button id="prevPageBtn" class="secondary-btn" style="padding: 8px 16px;" ${state.pdfCurrentPage <= 1 ? 'disabled' : ''}>
                                    <i class="fas fa-chevron-left"></i>
                                </button>
                                <span style="font-weight: 500;">Page ${state.pdfCurrentPage} of ${state.pdfTotalPages}</span>
                                <button id="nextPageBtn" class="secondary-btn" style="padding: 8px 16px;" ${state.pdfCurrentPage >= state.pdfTotalPages ? 'disabled' : ''}>
                                    <i class="fas fa-chevron-right"></i>
                                </button>
                            </div>
                            <div style="display: flex; align-items: center; gap: 12px;">
                                <button id="zoomOutBtn" class="secondary-btn" style="padding: 8px 12px;">
                                    <i class="fas fa-minus"></i>
                                </button>
                                <span style="font-size: 0.9rem; color: var(--muted);">${Math.round(state.pdfZoomLevel * 100 / 1.5)}%</span>
                                <button id="zoomInBtn" class="secondary-btn" style="padding: 8px 12px;">
                                    <i class="fas fa-plus"></i>
                                </button>
                            </div>
                        </div>
                        <div id="pdfCanvasContainer" style="flex: 1; overflow: auto; display: flex; justify-content: center; padding: 20px; position: relative;">
                            <canvas id="pdfCanvas" style="box-shadow: 0 4px 20px rgba(0,0,0,0.1);"></canvas>
                            <div id="pdfHighlightLayer" style="position: absolute; top: 20px; left: 50%; transform: translateX(-50%); pointer-events: none;"></div>
                        </div>
                    </div>
                    
                    <!-- Highlights Panel -->
                    <div style="width: 380px; display: flex; flex-direction: column; background: var(--surface-strong); border-radius: 12px; overflow: hidden;">
                        <div style="padding: 16px; border-bottom: 1px solid var(--line);">
                            <div style="display: flex; justify-content: space-between; align-items: center;">
                                <h4 style="margin: 0;">Highlights & Notes</h4>
                                <span class="muted" style="font-size: 0.85rem;">${state.pdfHighlights.length} saved</span>
                            </div>
                            <p class="muted" style="margin: 8px 0 0 0; font-size: 0.8rem;">Auto-saved to notes section</p>
                        </div>
                        <div style="flex: 1; overflow: auto; padding: 16px;">
                            ${state.pdfHighlights.length === 0 ? `
                                <p class="muted" style="text-align: center; padding: 40px 20px;">
                                    Select text and choose a color to highlight
                                </p>
                            ` : renderPdfHighlightsHierarchy()}
                        </div>
                    </div>
                </div>
            `}
        </section>
    `;
}

// ================= PDF VIEWER SUPPORT FUNCTIONS =================

// Save PDF library to localStorage
function savePdfLibrary() {
    try {
        // Don't save PDF data to localStorage (too large), save metadata only
        const libraryMetadata = state.pdfLibrary.map(item => ({
            id: item.id,
            name: item.name,
            type: item.type,
            parentId: item.parentId,
            children: item.children,
            highlights: item.highlights,
            createdAt: item.createdAt
        }));
        localStorage.setItem('pdfLibraryMetadata', JSON.stringify(libraryMetadata));
    } catch (e) {
        console.error("Failed to save PDF library:", e);
    }
}

// Load PDF library metadata from localStorage
function loadPdfLibrary() {
    try {
        const data = localStorage.getItem('pdfLibraryMetadata');
        if (data) {
            const metadata = JSON.parse(data);
            // PDF data is not persisted, only metadata
            state.pdfLibrary = metadata.map(item => ({
                ...item,
                pdfData: null // PDF data needs to be re-uploaded
            }));
        }
    } catch (e) {
        console.error("Failed to load PDF library:", e);
    }
}

// Render a specific PDF page to canvas
async function renderPdfPage(pdf, pageNumber) {
    const canvas = document.getElementById("pdfCanvas");
    if (!canvas) return;
    
    const page = await pdf.getPage(pageNumber);
    const scale = state.pdfZoomLevel;
    const viewport = page.getViewport({ scale });
    
    const context = canvas.getContext("2d");
    canvas.height = viewport.height;
    canvas.width = viewport.width;
    
    await page.render({
        canvasContext: context,
        viewport: viewport
    }).promise;
    
    // Setup text layer for selection
    setupTextLayer(page, canvas, viewport, scale);
    
    // Render existing highlights on this page
    renderHighlightsOnPage(pageNumber, viewport);
}

// Setup text layer for text selection
async function setupTextLayer(page, canvas, viewport, scale) {
    const container = document.getElementById("pdfCanvasContainer");
    if (!container) return;
    
    // Remove existing text layer
    const existingTextLayer = document.getElementById("pdfTextLayer");
    if (existingTextLayer) existingTextLayer.remove();
    
    // Create text layer
    const textLayer = document.createElement("div");
    textLayer.id = "pdfTextLayer";
    textLayer.style.position = "absolute";
    textLayer.style.top = "20px";
    textLayer.style.left = "50%";
    textLayer.style.transform = "translateX(-50%)";
    textLayer.style.width = canvas.width + "px";
    textLayer.style.height = canvas.height + "px";
    textLayer.style.zIndex = "5";
    textLayer.style.cursor = "text";
    
    container.appendChild(textLayer);
    
    // Get text content and create selectable spans
    const textContent = await page.getTextContent();
    textContent.items.forEach((item) => {
        if (item.str.trim()) {
            const span = document.createElement("span");
            span.textContent = item.str;
            span.style.position = "absolute";
            span.style.left = item.transform[4] * scale + "px";
            span.style.top = (item.transform[5]) * scale + "px";
            span.style.fontSize = Math.abs(item.transform[0]) * scale + "px";
            span.style.fontFamily = "sans-serif";
            span.style.color = "transparent";
            span.style.userSelect = "text";
            span.style.whiteSpace = "pre";
            textLayer.appendChild(span);
        }
    });
    
    // Add mouseup listener for text selection
    textLayer.addEventListener("mouseup", handlePdfTextSelection);
}

// Handle text selection in PDF (separate from general handleTextSelection)
function handlePdfTextSelection() {
    const selection = window.getSelection();
    const selectedText = selection.toString().trim();
    
    if (!selectedText) return;
    
    // Get selection coordinates
    const range = selection.getRangeAt(0);
    const rects = range.getClientRects();
    
    if (rects.length === 0) return;
    
    // Calculate highlight rectangle (union of all rects)
    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    for (const rect of rects) {
        minX = Math.min(minX, rect.left);
        minY = Math.min(minY, rect.top);
        maxX = Math.max(maxX, rect.right);
        maxY = Math.max(maxY, rect.bottom);
    }
    
    const canvas = document.getElementById("pdfCanvas");
    if (!canvas) return;
    
    const canvasRect = canvas.getBoundingClientRect();
    
    // Convert to canvas coordinates (adjust for current zoom level)
    const zoomScale = state.pdfZoomLevel;
    const highlightRect = {
        x: (minX - canvasRect.left) / zoomScale,
        y: (minY - canvasRect.top) / zoomScale,
        width: (maxX - minX) / zoomScale,
        height: (maxY - minY) / zoomScale
    };
    
    // Determine highlight type based on color
    let highlightType = "bullet";
    if (state.pdfCurrentHighlightColor === "#FFA500") {
        highlightType = "subtopic";
    } else if (state.pdfCurrentHighlightColor === "#3B82F6") {
        highlightType = "note";
    } else if (state.pdfCurrentHighlightColor === "#EF4444") {
        highlightType = "important";
    }
    
    // Create highlight
    const newHighlight = {
        id: Date.now().toString(),
        pageNumber: state.pdfCurrentPage,
        text: selectedText,
        rect: highlightRect,
        color: state.pdfCurrentHighlightColor,
        type: highlightType,
        timestamp: Date.now()
    };
    
    state.pdfHighlights.push(newHighlight);
    
    // Clear selection
    selection.removeAllRanges();
    
    // Save to PDF library
    if (state.pdfOpenPdfId) {
        const pdf = state.pdfLibrary.find(p => p.id === state.pdfOpenPdfId);
        if (pdf) {
            pdf.highlights = [...state.pdfHighlights];
            savePdfLibrary();
        }
    }
    
    // Auto-save to notes section
    void saveHighlightToNote(newHighlight).catch((err) => console.error("saveHighlightToNote:", err));
    
    // Re-render
    state.quietRender = true;
    renderApp();
    
    // Re-render page with new highlight
    pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
    pdfjsLib.getDocument(state.pdfOpenPdfData).promise.then(pdf => {
        renderPdfPage(pdf, state.pdfCurrentPage);
    });
    
    showNotice(`Highlight saved as ${highlightType}`);
}

// Save highlight to notes section (PDF): group under micro-topic headings like cloud highlights.
async function saveHighlightToNote(highlight) {
    if (!isLoggedIn() || !state.currentUser?.uid) {
        showNotice("Sign in to save highlights to Notes.");
        return;
    }
    const noteTitle = `PDF Notes: ${state.pdfOpenPdfName}`;
    const existingNote = state.userNotes.find((n) => n.title === noteTitle);

    const items = existingNote?.items ? [...existingNote.items] : [];
    const highlights = existingNote?.highlights ? [...existingNote.highlights] : [];

    const microTopic =
        highlight.type === "subtopic" && String(highlight.text || "").trim()
            ? String(highlight.text).trim()
            : `Page ${highlight.pageNumber ?? "?"}`;
    const microTopicKey = microTopic.toLowerCase();
    let headingIndex = items.findIndex(
        (item) => item?.type === "microTopicHeading" && String(item?.key || "").toLowerCase() === microTopicKey
    );
    if (headingIndex === -1) {
        items.push({
            type: "microTopicHeading",
            text: microTopic,
            key: microTopicKey,
            addedAt: new Date().toISOString()
        });
        headingIndex = items.length - 1;
    }

    let formattedText = String(highlight.text || "").trim();
    if (formattedText) {
        formattedText = formattedText.charAt(0).toUpperCase() + formattedText.slice(1);
    }

    const nextHighlightItem = {
        type: "highlight",
        text: formattedText,
        source: `PDF • ${state.pdfOpenPdfName || "PDF"} • p.${highlight.pageNumber}`,
        microTopic,
        addedAt: new Date().toISOString(),
        pdfPage: highlight.pageNumber,
        pdfColor: highlight.color
    };

    let insertIndex = headingIndex + 1;
    while (insertIndex < items.length && items[insertIndex]?.type !== "microTopicHeading") {
        insertIndex++;
    }
    items.splice(insertIndex, 0, nextHighlightItem);
    highlights.push({ ...highlight, microTopic });

    const content = expandNoteItemsForView(items)
        .map((item) => {
            if (item.type === "microTopicHeading") return `## ${item.text}`;
            if (item.type === "highlight" && item.pdfPage != null) {
                return `- ${item.text} (p.${item.pdfPage})`;
            }
            if (item.type === "highlight") return `- ${item.text}`;
            return "";
        })
        .filter(Boolean)
        .join("\n");

    const notePayload = {
        ...(existingNote || {}),
        id: existingNote?.id,
        title: noteTitle,
        subject: "PDF Notes",
        content,
        items,
        highlights
    };

    try {
        const saved = await saveUserNote(state.currentUser.uid, notePayload);
        const idx = state.userNotes.findIndex((n) => n.id === saved.id);
        if (idx >= 0) state.userNotes[idx] = saved;
        else state.userNotes.unshift(saved);
        state.quietRender = true;
        renderApp();
    } catch (err) {
        console.error("Failed to save PDF highlight to note:", err);
        showNotice("Failed to save highlight");
    }
}

// Render highlights on the current page
function renderHighlightsOnPage(pageNumber, viewport) {
    const highlightLayer = document.getElementById("pdfHighlightLayer");
    if (!highlightLayer) return;
    
    highlightLayer.innerHTML = '';
    
    const pageHighlights = state.pdfHighlights.filter(h => h.pageNumber === pageNumber);
    
    pageHighlights.forEach(highlight => {
        const highlightDiv = document.createElement("div");
        highlightDiv.style.position = "absolute";
        highlightDiv.style.left = highlight.rect.x * viewport.scale + "px";
        highlightDiv.style.top = highlight.rect.y * viewport.scale + "px";
        highlightDiv.style.width = highlight.rect.width * viewport.scale + "px";
        highlightDiv.style.height = highlight.rect.height * viewport.scale + "px";
        highlightDiv.style.backgroundColor = highlight.color + "40"; // Semi-transparent
        highlightDiv.style.border = "2px solid " + highlight.color;
        highlightDiv.style.pointerEvents = "none";
        highlightLayer.appendChild(highlightDiv);
    });
}

// Download PDF notes as formatted document
function downloadPdfNotes() {
    if (state.pdfHighlights.length === 0) {
        showNotice("No highlights to download", "error");
        return;
    }
    
    // Create HTML content for download
    let htmlContent = `
        <!DOCTYPE html>
        <html>
        <head>
            <title>Notes - ${escapeHtml(state.pdfOpenPdfName)}</title>
            <style>
                body { font-family: Arial, sans-serif; padding: 40px; max-width: 800px; margin: 0 auto; }
                h1 { color: #333; border-bottom: 2px solid #333; padding-bottom: 10px; }
                .subtopic { background: #FFA500; color: white; padding: 12px; border-radius: 6px; margin: 20px 0 10px 0; }
                .subtopic h3 { margin: 0; }
                .bullet { padding: 10px; background: #f5f5f5; border-left: 4px solid #22C55E; margin: 8px 0 8px 20px; }
                .page-ref { font-size: 0.8rem; color: #666; }
                .note { padding: 10px; background: #e3f2fd; border-left: 4px solid #3B82F6; margin: 8px 0 8px 20px; }
                .important { padding: 10px; background: #ffebee; border-left: 4px solid #EF4444; margin: 8px 0 8px 20px; }
            </style>
        </head>
        <body>
            <h1>Notes: ${escapeHtml(state.pdfOpenPdfName)}</h1>
            <p style="color: #666; margin-bottom: 30px;">Generated on ${new Date().toLocaleDateString()}</p>
    `;
    
    let currentSubtopic = null;
    
    state.pdfHighlights.forEach(highlight => {
        if (highlight.type === 'subtopic') {
            if (currentSubtopic) {
                htmlContent += '</div>';
            }
            currentSubtopic = highlight.text;
            htmlContent += `
                <div class="subtopic">
                    <h3>${escapeHtml(highlight.text)}</h3>
                    <span class="page-ref">Page ${highlight.pageNumber}</span>
                </div>
                <div style="padding-left: 20px;">
            `;
        } else {
            const className = highlight.type === 'note' ? 'note' : highlight.type === 'important' ? 'important' : 'bullet';
            htmlContent += `
                <div class="${className}">
                    <p>${escapeHtml(highlight.text)}</p>
                    <span class="page-ref">Page ${highlight.pageNumber}</span>
                </div>
            `;
        }
    });
    
    if (currentSubtopic) {
        htmlContent += '</div>';
    }
    
    htmlContent += `
        </body>
        </html>
    `;
    
    // Create blob and download
    const blob = new Blob([htmlContent], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `Notes_${state.pdfOpenPdfName.replace('.pdf', '')}.html`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    
    showNotice("Notes downloaded successfully");
}

