// Render highlights with hierarchy (subtopics as headings)
function renderPdfHighlightsHierarchy() {
    const subtopics = {};
    const bullets = [];
    
    state.pdfHighlights.forEach((highlight, index) => {
        if (highlight.type === 'subtopic') {
            if (!subtopics[highlight.text]) {
                subtopics[highlight.text] = [];
            }
        } else {
            bullets.push({ ...highlight, index });
        }
    });
    
    let html = '';
    let currentSubtopic = null;
    
    state.pdfHighlights.forEach((highlight, index) => {
        if (highlight.type === 'subtopic') {
            if (currentSubtopic) {
                html += '</div>';
            }
            currentSubtopic = highlight.text;
            html += `
                <div style="margin-bottom: 20px;">
                    <div style="padding: 10px 12px; background: ${highlight.color}; border-radius: 6px; margin-bottom: 8px;">
                        <h5 style="margin: 0; color: white; font-size: 0.95rem;">${escapeHtml(highlight.text)}</h5>
                        <span style="font-size: 0.75rem; color: rgba(255,255,255,0.8);">Page ${highlight.pageNumber}</span>
                    </div>
                    <div style="padding-left: 12px;">
            `;
        } else {
            html += `
                <div style="padding: 10px 12px; background: var(--surface-weak); border-radius: 6px; margin-bottom: 8px; border-left: 3px solid ${highlight.color};">
                    <div style="display: flex; justify-content: space-between; align-items: start;">
                        <p style="margin: 0; font-size: 0.85rem; line-height: 1.4;">${escapeHtml(highlight.text.substring(0, 200))}${highlight.text.length > 200 ? '...' : ''}</p>
                        <button class="delete-highlight-btn" data-index="${index}" style="background: none; border: none; color: var(--muted); cursor: pointer; padding: 4px; margin-left: 8px;">
                            <i class="fas fa-times"></i>
                        </button>
                    </div>
                    <span style="font-size: 0.7rem; color: var(--muted);">Page ${highlight.pageNumber}</span>
                </div>
            `;
        }
    });
    
    if (currentSubtopic) {
        html += '</div></div>';
    }
    
    return html;
}

let lastSyncTimestamp = 0;
async function syncUserSessionData(force = false) {
    if (!isLoggedIn()) return;
    
    const now = Date.now();
    // Only auto-sync every 60s unless forced or view changed
    if (!force && lastSyncTimestamp && (now - lastSyncTimestamp < 60000)) return;
    
    try {
        const freshStates = await loadAllQuestionStates(state.currentUser.uid);
        if (freshStates && freshStates.length) {
            state.questionStates = freshStates;
            lastSyncTimestamp = now;
            // Quiet render to reflect changes without reset
            state.quietRender = true;
            renderApp();
        }
    } catch (error) {
        console.warn("Auto-sync failed:", error);
    }
}

function renderView(test, attempt, summary) {
    const insights = buildSmartInsights(attempt);
    if (state.currentView === "practice") return attempt && !attempt.submittedAt ? renderRunnerPaper(test, attempt) : renderConfigurator(test);
    if (state.currentView === "study") return renderStudyMode();
    if (state.currentView === "review") return renderReviewSimplified();
    if (state.currentView === "analytics") return renderAnalyticsCompact();
    if (state.currentView === "flashcards" || state.currentView === "spaced") return renderFlashcards();
    if (state.currentView === "folders") return renderFolders();
    if (state.currentView === "notes") return renderNotesPanel();
    if (state.currentView === "settings") return renderSettings();
    if (state.currentView === "pyqAnalysis") return renderPyqAnalysis();
    if (state.currentView === "syllabusTracker") return renderTracker();
    if (state.currentView === "admin") return isLoggedIn()
        ? renderAdminCompact(test)
        : renderAccessGate("Admin console is locked", "Import tools, duplicate review, topic correction, and provider management are available only after sign in.", "Admin Access");
    return renderHomeLanding();
}

