function renderRunnerPaper(test, attempt) {
    const pages = chunkQuestions(attempt.questions, 6);
    const currentPage = Math.floor(attempt.currentIndex / 6);
    const pageQuestions = pages[currentPage] || [];
    const answeredCount = attempt.questions.filter((question) => question.selectedAnswer).length;
    const reviewCount = attempt.questions.filter((question) => question.markForReview).length;
    // For shuffled/custom pools, show progress-oriented numbering (1..N) instead of the original paper's numbering.
    const currentQuestionNumber = attempt.currentIndex + 1;
    return `
        <section class="paper-shell">
            <div class="paper-topbar">
                <div>
                    <p class="eyebrow">Attempt paper</p>
                    <h3>${test.title}</h3>
                    <p class="muted">Page ${currentPage + 1} of ${pages.length} • ${answeredCount} answered • ${reviewCount} review</p>
                </div>
                <div class="paper-actions">
                    <div class="timer-pill">${attempt.timerMode === "timed" ? `Elapsed ${formatElapsedSince(attempt.startedAt)} • Time left ${formatRemaining(state.timeRemainingMs)}` : `Elapsed ${formatElapsedSince(attempt.startedAt)} • Untimed`}</div>
                    <button class="ghost-btn palette-toggle-btn" type="button" id="paletteToggleBtn">${state.paletteOpen ? "Hide palette" : "Show palette"}</button>
                    <button class="primary-btn" type="button" id="submitAttemptBtn">Submit test</button>
                </div>
            </div>
            <div class="paper-status-strip">
                <span class="paper-pill current">Current question Q${currentQuestionNumber}</span>
                <span class="paper-pill">Current page ${currentPage + 1}</span>
                <span class="paper-pill">${answeredCount}/${attempt.questions.length} answered</span>
            </div>
            <div class="paper-layout">
                <div class="a4-paper">
                    <div class="paper-grid">
                        ${pageQuestions.map((q) => {
                            const index = attempt.questions.findIndex((item) => item.id === q.id);
                            const displayNumber = index + 1;
                            return `<article class="paper-question ${attempt.currentIndex === index ? "focus-question" : ""}">
                                <div class="paper-question-head">
                                    <div class="question-meta"><span class="chip">Q${displayNumber}</span></div>
                                    <button type="button" class="ghost-btn small ${q.markForReview ? "review-marked-btn" : ""}" data-toggle-review="${index}">${q.markForReview ? "Review marked" : "Mark review"}</button>
                                </div>
                                <div class="question-text-block compact-question">${renderQuestionContent(q)}</div>
                                <div class="option-list compact-options">${orderedOptions(q.options).map(([key, value]) => `<label class="option-row ${q.selectedAnswer === key ? "selected" : ""}"><input type="radio" name="answerOption-${index}" value="${key}" data-qindex="${index}" ${q.selectedAnswer === key ? "checked" : ""}><span><strong>${key})</strong> ${value}</span></label>`).join("")}</div>
                                <div class="review-tag-layer"><span class="label">Confidence</span><div class="stacked-chips">${appConfig.confidenceTags.map((tag) => `<button type="button" class="chip ${q.confidence === tag ? "active-chip" : ""}" data-confidence="${tag}" data-qindex="${index}">${tag}</button>`).join("")}</div></div>
                            </article>`;
                        }).join("")}
                    </div>
                    <div class="practice-footer">
                        <button class="ghost-btn" type="button" id="prevPageBtn" ${currentPage === 0 ? "disabled" : ""}>Previous page</button>
                        <button class="ghost-btn" type="button" id="saveNextBtn">Save & Next</button>
                        <button class="primary-btn" type="button" id="practiceSaveTagsBtn" title="Save all tags and folders for current page">Save Tags</button>
                        <button class="primary-btn" type="button" id="practiceSaveFoldersBtn" title="Save all folders for current page to database">Save Folders</button>
                        <button class="ghost-btn" type="button" id="nextPageBtn" ${currentPage === pages.length - 1 ? "disabled" : ""}>Next page</button>
                    </div>
                </div>
                <aside class="palette-panel ${state.paletteOpen ? "open" : ""}">
                    <div class="palette-head"><p class="eyebrow">Question Palette</p><p class="muted">Answered / Unanswered / Review</p></div>
                    <div class="palette-grid">
                        ${attempt.questions.map((question, index) => {
                            const statusClass = question.markForReview ? "review" : question.selectedAnswer ? "answered" : "unanswered";
                            const pageIndex = Math.floor(index / 6) + 1;
                            return `<button type="button" class="palette-btn ${statusClass} ${attempt.currentIndex === index ? "current" : ""}" data-palette-index="${index}"><span>${index + 1}</span><small>P${pageIndex}</small></button>`;
                        }).join("")}
                    </div>
                    <div class="palette-legend">
                        <span><i class="legend-box answered"></i> Answered</span>
                        <span><i class="legend-box unanswered"></i> Unanswered</span>
                        <span><i class="legend-box review"></i> Review</span>
                    </div>
                </aside>
            </div>
            ${state.submitConfirmOpen ? `
                <div class="modal-backdrop">
                    <div class="confirm-modal">
                        <p class="eyebrow">Submit Attempt</p>
                        <h3>Submit this paper now?</h3>
                        <p class="muted">You have answered ${answeredCount} out of ${attempt.questions.length} questions. Unanswered questions will be submitted as blank.</p>
                        <div class="modal-actions">
                            <button class="ghost-btn" type="button" id="cancelSubmitBtn" ${state.submitBusy ? "disabled" : ""}>Keep attempting</button>
                            <button class="primary-btn" type="button" id="confirmSubmitBtn" ${state.submitBusy ? "disabled" : ""}>${state.submitBusy ? "Submitting..." : "Confirm submit"}</button>
                        </div>
                    </div>
                </div>
            ` : ""}
        </section>
    `;
}

function renderReviewEnhanced() {
    // Sync attempts from Supabase when review section loads
    ensureReviewAttemptsSynced();
    
    const attempted = submittedAttempts();
    if (!attempted.length) return `<section class="panel empty-panel"><p class="eyebrow">Review</p><h3>No submitted attempt yet</h3><p class="muted">Submit a test to unlock tagging and difficulty review.</p></section>`;
    const selected = buildCurrentReviewContext();
    const attempt = selected?.attempt;
    const reviewTest = selected?.test;
    if (!attempt?.submittedAt || !reviewTest) return `<section class="panel empty-panel"><p class="eyebrow">Review</p><h3>No submitted attempt yet</h3><p class="muted">Submit a test to unlock tagging and difficulty review.</p></section>`;
    const queue = buildReviewQueue(attempt, state.reviewFilters);
    const incorrectCount = attempt.questions.filter((question) => question.selectedAnswer && question.selectedAnswer !== question.correctAnswer).length;
    const revisionPriorityCount = attempt.questions.filter((question) => (question.reviewTags || []).includes("Must Revise")).length;
    const learningFilterItems = allLearningTags().map((tag) => [`tag:${tag}`, tag]);
    const filterGroups = [
        {
            title: "Base filters",
            items: [["incorrect", "Incorrect only"], ["correct", "Correct only"], ["notAttempted", "Not Attempted"], ["all", "All attempted"], ["allQuestions", "All questions"], ["pyq", "PYQ"]]
        },
        {
            title: "Learning tags",
            items: learningFilterItems
        }
    ];
    const subjectOptions = reviewAttemptSubjects();
    const sectionOptions = reviewAttemptSectionGroups();
    const microTopicOptions = reviewAttemptMicroTopics();
    return `
        <section class="panel">
            <div class="section-head compact-section-head"><div><p class="eyebrow">Revise & Review</p><h3>Choose a paper to review</h3><p class="muted">Pick a submitted test, analyze weak areas, revise, retest, and improve.</p></div></div>
            <div class="workflow-inline muted"><strong>Choose paper</strong><span>→</span><strong>Review mistakes</strong><span>→</span><strong>Revise</strong><span>→</span><strong>Retest</strong><span>→</span><strong>Improve</strong></div>
            <div class="attempt-select-row">
                <select id="reviewAttemptSelect" class="compact-select">
                    ${attempted.map(({ test: itemTest, attempt: itemAttempt }) => `<option value="${itemTest.id}" ${state.reviewTestId === itemTest.id ? "selected" : ""}>${itemTest.title} • ${new Date(itemAttempt.submittedAt).toLocaleDateString("en-IN")}</option>`).join("")}
                </select>
                <button class="primary-btn small" type="button" id="reviewAttemptOpenBtn">Review</button>
                <button class="ghost-btn small danger-btn" type="button" id="reviewAttemptDeleteBtn">Delete history</button>
            </div>
        </section>
        <section class="panel revision-launch-panel">
            <div class="section-head compact-section-head">
                <div>
                    <p class="eyebrow">Revision System</p>
                    <h3>Mistake → Analysis → Revision → Improvement</h3>
                    <p class="muted">Launch a fresh practice attempt directly from this reviewed paper without hunting for the questions again.</p>
                </div>
            </div>
            <div class="revision-quick-grid">
                <article class="mini-stat">
                    <span class="label">Visible in review</span>
                    <strong>${queue.length}</strong>
                    <small>Questions match the currently active review filters.</small>
                </article>
                <article class="mini-stat">
                    <span class="label">Incorrect</span>
                    <strong>${incorrectCount}</strong>
                    <small>Questions answered wrong in the selected attempt.</small>
                </article>
                <article class="mini-stat">
                    <span class="label">Revision priority</span>
                    <strong>${revisionPriorityCount}</strong>
                    <small>Questions carrying an RPG revision priority grade.</small>
                </article>
                <article class="mini-stat">
                    <span class="label">Question bank</span>
                    <strong>${reviewTest.questions.length}</strong>
                    <small>Total questions available in this paper.</small>
                </article>
            </div>
            <div class="stacked-chips revision-action-row">
                <button class="primary-btn small" type="button" data-review-practice="filtered">Re-practice current filter set</button>
                <button class="ghost-btn small" type="button" data-review-practice="incorrect">Re-practice incorrect only</button>
                <button class="ghost-btn small" type="button" data-review-practice="learningTags">Re-practice learning tags</button>
                <button class="ghost-btn small" type="button" data-review-practice="shuffle">Shuffle full paper</button>
                <button class="ghost-btn small" type="button" id="openReviewDownloadBtn">Download review pack</button>
            </div>
        </section>
        <section class="panel">
            <div class="section-head"><div><p class="eyebrow">Review Filters</p><h3>${reviewTest.title}</h3><p class="muted">Go straight to incorrect or revision-marked questions for this test.</p></div></div>
            <div class="review-filter-groups">
                ${filterGroups.map((group) => `
                    <div class="review-filter-layer">
                        <span class="label">${group.title}</span>
                        <div class="stacked-chips">${group.items.map(([value, label]) => `<button type="button" class="chip ${state.reviewFilters.includes(value) ? "active-chip" : ""}" data-review-filter="${value}">${label}</button>`).join("")}</div>
                    </div>
                `).join("")}
            </div>
        </section>
        <section class="review-grid">
            ${queue.map((question) => `
                <article class="review-card" data-review-question-test-id="${escapeHtml(String(question.__attemptTestId || reviewTest.id || ""))}">
                    <div class="review-head">
                        <span class="label">Q${question.questionNumber}</span>
                        <button class="ghost-btn small" type="button" data-reset-question="${question.id}" data-attempt-test="${question.__attemptTestId || reviewTest.id}">Reset history</button>
                    </div>
                    <div class="question-text-block compact-question"><h3>Q${question.questionNumber}.</h3><div>${renderQuestionContent(question)}</div></div>
                    <p class="muted"><strong>Your answer:</strong> ${question.selectedAnswer || "Unattempted"} • <strong>Correct:</strong> ${question.correctAnswer}</p>
                    <div class="review-options">
                        ${orderedOptions(question.options).map(([key, value]) => {
                            const isCorrect = question.correctAnswer === key;
                            const isSelected = question.selectedAnswer === key;
                            const optionState = isCorrect && isSelected
                                ? "review-option correct selected"
                                : isCorrect
                                    ? "review-option correct"
                                    : isSelected
                                        ? "review-option incorrect selected"
                                        : "review-option";
                            const optionLabel = isCorrect && isSelected
                                ? '<span class="review-badge success">Your correct answer</span>'
                                : isCorrect
                                    ? '<span class="review-badge success">Correct answer</span>'
                                    : isSelected
                                        ? '<span class="review-badge danger">Your answer</span>'
                                        : "";
                            return `<div class="${optionState}"><div class="review-option-main"><strong>${key})</strong><span>${value}</span></div>${optionLabel}</div>`;
                        }).join("")}
                    </div>
                    <div class="review-tag-cluster">
                        <div class="stacked-chips compact-review-tags">${allLearningTags().map((tag) => {
                            const active = (question.reviewTags || []).includes(tag);
                            return `<button type="button" class="chip ${active ? "active-chip" : ""}" data-review-tag="${tag}" data-question-id="${question.id}" data-attempt-test="${question.__attemptTestId || reviewTest.id}">${tag}</button>`;
                        }).join("")}</div>
                        ${(question.savedFolders || []).length ? `<div class="stacked-chips compact-review-tags">${question.savedFolders.map((folder) => `<span class="chip">${folder}</span>`).join("")}</div>` : ""}
                    </div>
                    <div class="details-block"><p><strong>Explanation</strong></p><div>${renderSimpleMarkdown(question.explanationMarkdown)}</div>${question.highlightText ? `<p><strong>Saved highlight:</strong> ${escapeHtml(question.highlightText)}</p>` : ""}${question.note ? `<p><strong>Personal note:</strong> ${escapeHtml(question.note)}</p>` : ""}<p class="muted"><strong>Source:</strong> ${question.source.sourceText}</p><p class="muted"><strong>Topic:</strong> ${question.microTopic}</p></div>
                </article>
            `).join("")}
        </section>
    `;
}

function renderConfigurator(test) {
    return renderPracticeSetup();
    const practiceSectionGroups = sectionGroupsForSubject(state.practiceTopicSubject);
    const practiceMicroTopics = microTopicsForPracticeSelection(state.practiceTopicSubject, state.practiceTopicSectionGroup);
    const syllabusPoolCount = buildSyllabusPracticeQuestions().length;
    return `
        <section class="panel">
            <div class="section-head"><div><p class="eyebrow">Practice Setup</p><h3>Choose how you want to start</h3><p class="muted">Start an original paper or build a topic-wise practice set from selected providers and micro topics.</p></div></div>
        </section>
        <section class="panel practice-launch-shell">
            <div class="start-test-card-inner start-test-card-expanded">
                <div class="stacked-chips">
                    <button class="chip ${state.practiceLaunchMode === "test" ? "active-chip" : ""}" type="button" data-practice-launch="test">Original Test</button>
                    <button class="chip ${state.practiceLaunchMode === "syllabus" ? "active-chip" : ""}" type="button" data-practice-launch="syllabus">Topic-wise Practice</button>
                </div>
                ${state.practiceLaunchMode === "test" ? `
                    <div class="start-test-controls">
                        ${hasFacetIndexing() ? `
                            <label><span>Institute</span><select id="launchInstituteSelect">${availableInstitutes().map((item) => typeof item === "string" ? `<option value="${item}" ${item === state.selectedInstitute ? "selected" : ""}>${item}</option>` : `<option value="${item.id}" ${item.id === state.selectedInstitute ? "selected" : ""}>${escapeHtml(item.label || item.id)}</option>`).join("")}</select></label>
                            <label><span>Programme</span><select id="launchProgrammeSelect">${availableProgrammes(state.selectedInstitute).map((item) => typeof item === "string" ? `<option value="${item}" ${item === state.selectedProgramme ? "selected" : ""}>${item}</option>` : `<option value="${item.id}" ${item.id === state.selectedProgramme ? "selected" : ""}>${escapeHtml(item.label || item.id)}</option>`).join("")}</select></label>
                        ` : `<label><span>Provider</span><select id="launchProviderSelect">${availableProviders().map((provider) => `<option value="${provider}" ${provider === state.selectedProvider ? "selected" : ""}>${provider}</option>`).join("")}</select></label>`}
                        <label><span>Subject</span><select id="launchSubjectSelect">${availableSubjects().map((subject) => `<option value="${subject}" ${subject === state.selectedSubject ? "selected" : ""}>${subject}</option>`).join("")}</select></label>
                        <label><span>Section Group</span><select id="launchSectionGroupSelect">${availableSectionGroups().map((section) => `<option value="${section}" ${section === state.selectedSectionGroup ? "selected" : ""}>${section}</option>`).join("")}</select></label>
                        <label><span>Test</span><select id="launchTestSelect">${visibleTests().length ? visibleTests().map((item) => `<option value="${item.id}" ${item.id === state.selectedTestId ? "selected" : ""}>${item.title}</option>`).join("") : `<option value="">No test available</option>`}</select></label>
                    </div>
                    <button class="primary-btn start-test-btn" id="launchStartBtn" type="button">Start original test</button>
                ` : `
                    <div class="start-test-controls">
                    <label><span>Subject</span><select id="practiceTopicSubject">${["All Subjects", ...allAvailableSubjects().filter((subject) => subject !== "All")].map((subject) => `<option value="${subject}" ${state.practiceTopicSubject === subject ? "selected" : ""}>${subject}</option>`).join("")}</select></label>
                        <label><span>Section Group</span><select id="practiceTopicSectionGroup">${practiceSectionGroups.map((item) => `<option value="${item}" ${state.practiceTopicSectionGroup === item ? "selected" : ""}>${item}</option>`).join("")}</select></label>
                        <label><span>Question Count</span><input id="syllabusQuestionCount" type="number" min="5" max="100" value="${state.customQuestionCount}"></label>
                    </div>
                    <div class="start-test-multiselect">
                        <span class="label">Providers</span>
                        <div class="stacked-chips">${availableProviders().map((provider) => `<button type="button" class="chip ${isPracticeProviderChipActive(provider) ? "active-chip" : ""}" data-practice-provider="${provider}">${provider}</button>`).join("")}</div>
                    </div>
                    <div class="start-test-multiselect">
                        <span class="label">Micro Topics</span>
                        <div class="stacked-chips">${practiceMicroTopics.filter((item) => item !== "All").map((item) => `<button type="button" class="chip ${state.practiceMicroTopicFilters.includes(item) ? "active-chip" : ""}" data-practice-microtopic="${item}">${item}</button>`).join("")}</div>
                    </div>
                    <div class="stacked-chips launch-inline-checks">
                        <label class="inline-check"><input id="syllabusPyqOnly" type="checkbox" ${state.revisionPyqOnly ? "checked" : ""}><span>PYQ only</span></label>
                        <label class="inline-check"><input id="syllabusShuffle" type="checkbox" ${state.customShuffle ? "checked" : ""}><span>Shuffle</span></label>
                    </div>
                    <p class="muted">${syllabusPoolCount} matching questions currently available for this selection.</p>
                    <button class="primary-btn start-test-btn" id="launchTopicStartBtn" type="button">Start topic-wise practice</button>
                `}
            </div>
        </section>
    `;
    return `
        <section class="panel">
            <div class="section-head"><div><p class="eyebrow">Practice Setup</p><h3>Choose how you want to start</h3><p class="muted">Start from a named paper or build a topic practice set from syllabus tags across imported tests.</p></div></div>
            <div class="stacked-chips">
                <button class="chip ${state.practiceLaunchMode === "test" ? "active-chip" : ""}" type="button" data-practice-launch="test">Start by Test Name</button>
                <button class="chip ${state.practiceLaunchMode === "syllabus" ? "active-chip" : ""}" type="button" data-practice-launch="syllabus">Start by Syllabus / Topic</button>
            </div>
        </section>

        ${state.practiceLaunchMode === "test" ? `
            <section class="two-col-grid">
                <section class="panel">
                    <div class="section-head"><div><p class="eyebrow">Selected Paper</p><h3>${test.title}</h3></div></div>
                    <div class="start-test-meta">
                        <article><span class="label">Institute</span><strong>${testInstituteValue(test) || "-"}</strong></article>
                        <article><span class="label">Subject</span><strong>${testPrimarySubjectValue(test) || "-"}</strong></article>
                        <article><span class="label">Questions</span><strong>${test.questions.length}</strong></article>
                        <article><span class="label">Minutes</span><strong>${test.defaultMinutes}</strong></article>
                    </div>
                    <p class="muted">Use this when you want to attempt a specific paper end to end.</p>
                </section>
                <section class="panel">
                    <form id="practiceConfigForm" class="config-grid">
                        <label><span>Explanation mode</span><select id="explanationMode"><option value="ask">Ask every test</option><option value="immediate">Show after each question</option><option value="afterSubmit">Show only after submission</option></select></label>
                        <label><span>Timer mode</span><select id="timerMode"><option value="ask">Ask every test</option><option value="timed">Timed</option><option value="untimed">Untimed</option></select></label>
                        <label><span>Minutes if timed</span><input id="timerMinutes" type="number" min="1" max="180" value="${test.defaultMinutes}"></label>
                        <button class="primary-btn" type="submit">Start test</button>
                    </form>
                </section>
            </section>
        ` : `
            <section class="two-col-grid">
                <section class="panel">
                    <div class="section-head"><div><p class="eyebrow">Syllabus Practice</p><h3>Build a mixed topic set</h3></div></div>
                    <form id="syllabusPracticeForm" class="config-grid">
                    <label><span>Subject</span><select id="practiceTopicSubject">${["All Subjects", ...allAvailableSubjects().filter((subject) => subject !== "All")].map((subject) => `<option value="${subject}" ${state.practiceTopicSubject === subject ? "selected" : ""}>${subject}</option>`).join("")}</select></label>
                        <label><span>Section group</span><select id="practiceTopicSectionGroup">${practiceSectionGroups.map((item) => `<option value="${item}" ${state.practiceTopicSectionGroup === item ? "selected" : ""}>${item}</option>`).join("")}</select></label>
                        <label><span>Micro topic</span><select id="practiceTopicMicroTopic">${practiceMicroTopics.map((item) => `<option value="${item}" ${state.practiceTopicMicroTopic === item ? "selected" : ""}>${item}</option>`).join("")}</select></label>
                        <label><span>Question count</span><input id="syllabusQuestionCount" type="number" min="5" max="100" value="${state.customQuestionCount}"></label>
                        <label class="inline-check"><input id="syllabusPyqOnly" type="checkbox" ${state.revisionPyqOnly ? "checked" : ""}><span>PYQ only</span></label>
                        <label class="inline-check"><input id="syllabusShuffle" type="checkbox" ${state.customShuffle ? "checked" : ""}><span>Shuffle questions</span></label>
                        <button class="primary-btn" type="submit">Start topic practice</button>
                    </form>
                </section>
                <section class="panel">
                    <div class="section-head"><div><p class="eyebrow">What will open</p><h3>${state.practiceTopicMicroTopic === "All" ? state.practiceTopicSubject : state.practiceTopicMicroTopic}</h3></div></div>
                    <div class="start-test-meta">
                        <article><span class="label">Subject</span><strong>${state.practiceTopicSubject}</strong></article>
                        <article><span class="label">Section</span><strong>${state.practiceTopicSectionGroup}</strong></article>
                        <article><span class="label">Pool size</span><strong>${syllabusPoolCount}</strong></article>
                        <article><span class="label">Source mix</span><strong>Across imported tests</strong></article>
                    </div>
                    <p class="muted">This path is for practice like: choose <strong>Fundamental Rights</strong> and attempt all matching questions from across the imported test library.</p>
                </section>
            </section>
        `}
    `;
}

function renderReviewSimplified() {
    // Sync attempts from Supabase when review section loads
    ensureReviewAttemptsSynced();
    
    const attempted = submittedAttempts();
    if (!attempted.length) return `<section class="panel empty-panel"><p class="eyebrow">Review</p><h3>No submitted attempt yet</h3><p class="muted">Submit a test to unlock tagging and revision review.</p></section>`;
    const selected = buildCurrentReviewContext();
    const attempt = selected?.attempt;
    const reviewTest = selected?.test;
    if (!selected) {
        const subjectOptions = reviewAttemptSubjects();
        const sectionOptions = reviewAttemptSectionGroups();
        return `
            <section class="panel">
                <div class="section-head compact-section-head"><div><p class="eyebrow">Revise & Review</p><h3>Choose what to revise</h3><p class="muted">Select the paper or topic scope first, then click Review.</p></div></div>
                <div class="review-scope-grid">
                    <label><span>Revise by</span><select id="reviewSelectionMode" class="compact-select"><option value="test" ${state.reviewSelectionMode === "test" ? "selected" : ""}>Test Paper Wise</option><option value="topic" ${state.reviewSelectionMode === "topic" ? "selected" : ""}>Topic Wise</option></select></label>
                    ${state.reviewSelectionMode === "topic" ? `<label><span>Subject</span><select id="reviewSubjectSelect" class="compact-select">${subjectOptions.map((item) => `<option value="${item}" ${state.reviewSubject === item ? "selected" : ""}>${item}</option>`).join("")}</select></label>` : ""}
                    ${state.reviewSelectionMode === "topic" ? `<label><span>Section Group</span><select id="reviewSectionGroupSelect" class="compact-select">${sectionOptions.map((item) => `<option value="${item}" ${state.reviewSectionGroup === item ? "selected" : ""}>${item}</option>`).join("")}</select></label>` : ""}
                    ${state.reviewSelectionMode === "topic" ? `<label class="review-scope-microtheme"><span>Micro-theme</span><div style="display:flex;flex-wrap:wrap;align-items:center;gap:10px;margin-top:4px;"><span class="muted" style="flex:1;min-width:0;">${escapeHtml(state.reviewMicroTopic)}</span><button type="button" class="ghost-btn small" id="reviewMicroTopicModalBtn">Choose…</button></div></label>` : ""}
                    ${state.reviewSelectionMode === "test" ? `<label class="review-scope-wide"><span>Test Paper</span><select id="reviewAttemptSelect" class="compact-select"><option value="">Select test paper</option>${attempted.map(({ test: itemTest, attempt: itemAttempt }) => `<option value="${itemTest.id}" ${state.reviewTestId === itemTest.id ? "selected" : ""}>${itemTest.title} • ${new Date(itemAttempt.submittedAt).toLocaleDateString("en-IN")}</option>`).join("")}</select></label>` : ""}
                    <div class="review-scope-actions"><button class="primary-btn small" type="button" id="reviewAttemptOpenBtn">Review</button></div>
                </div>
                ${renderSourceScopeToggle(state.practiceSourceFilter)}
            </section>
        `;
    }
    if (!attempt?.questions?.length || !reviewTest) return `<section class="panel empty-panel"><p class="eyebrow">Review</p><h3>No revision set available</h3><p class="muted">Try another review selection.</p></section>`;

    const filteredPool = attempt.questions.filter(questionMatchesSourceFilters);
    const queue = buildReviewQueue({ ...attempt, questions: filteredPool }, state.reviewFilters).slice(0, 20);
    const incorrectCount = filteredPool.filter((question) => question.selectedAnswer && question.selectedAnswer !== question.correctAnswer).length;
    const revisionPriorityCount = filteredPool.filter((question) => (question.reviewTags || []).includes("Must Revise")).length;
    const learningFilterItems = allLearningTags().map((tag) => [`tag:${tag}`, tag]);
    const filterGroups = [
        {
            title: "Base filters",
            items: [["incorrect", "Incorrect only"], ["correct", "Correct only"], ["notAttempted", "Not Attempted"], ["all", "All attempted"], ["allQuestions", "All questions"], ["pyq", "PYQ"]]
        },
        {
            title: "Learning tags",
            items: learningFilterItems
        }
    ];
    const subjectOptions = reviewAttemptSubjects();
    const sectionOptions = reviewAttemptSectionGroups();

    return `
        <section class="panel">
            <div class="section-head compact-section-head"><div><p class="eyebrow">Revise & Review</p><h3>Choose what to revise</h3><p class="muted">Choose a past paper directly, or open a combined revision set by topic.</p></div></div>
            <div class="workflow-inline muted"><strong>Choose scope</strong><span>→</span><strong>Review mistakes</strong><span>→</span><strong>Revise</strong><span>→</span><strong>Retest</strong><span>→</span><strong>Improve</strong></div>
            <div class="review-scope-grid">
                <label><span>Revise by</span><select id="reviewSelectionMode" class="compact-select"><option value="test" ${state.reviewSelectionMode === "test" ? "selected" : ""}>Test Paper Wise</option><option value="topic" ${state.reviewSelectionMode === "topic" ? "selected" : ""}>Topic Wise</option></select></label>
                ${state.reviewSelectionMode === "topic" ? `<label><span>Subject</span><select id="reviewSubjectSelect" class="compact-select">${subjectOptions.map((item) => `<option value="${item}" ${state.reviewSubject === item ? "selected" : ""}>${item}</option>`).join("")}</select></label>` : ""}
                ${state.reviewSelectionMode === "topic" ? `<label><span>Section Group</span><select id="reviewSectionGroupSelect" class="compact-select">${sectionOptions.map((item) => `<option value="${item}" ${state.reviewSectionGroup === item ? "selected" : ""}>${item}</option>`).join("")}</select></label>` : ""}
                ${state.reviewSelectionMode === "topic" ? `<label class="review-scope-microtheme"><span>Micro-theme</span><div style="display:flex;flex-wrap:wrap;align-items:center;gap:10px;margin-top:4px;"><span class="muted" style="flex:1;min-width:0;">${escapeHtml(state.reviewMicroTopic)}</span><button type="button" class="ghost-btn small" id="reviewMicroTopicModalBtn">Choose…</button></div></label>` : ""}
                ${state.reviewSelectionMode === "test" ? `<label class="review-scope-wide"><span>Test Paper</span><select id="reviewAttemptSelect" class="compact-select"><option value="">Select test paper</option>${attempted.map(({ test: itemTest, attempt: itemAttempt }) => `<option value="${itemTest.id}" ${state.reviewTestId === itemTest.id ? "selected" : ""}>${itemTest.title} • ${new Date(itemAttempt.submittedAt).toLocaleDateString("en-IN")}</option>`).join("")}</select></label>` : ""}<div class="review-scope-actions"><button class="primary-btn small" type="button" id="reviewAttemptOpenBtn">Review</button></div>
            </div>
            ${renderSourceScopeToggle(state.practiceSourceFilter)}
            <div class="attempt-select-row">
                <span class="muted"><strong>Current revision set:</strong> ${selected.label}</span>
                ${selected.canDeleteHistory ? `<button class="ghost-btn small danger-btn" type="button" id="reviewAttemptDeleteBtn">Delete history</button>` : ""}
            </div>
        </section>
        <section class="panel revision-launch-panel">
            <div class="section-head compact-section-head">
                <div>
                    <p class="eyebrow">Revision System</p>
                    <h3>Mistake → Analysis → Revision → Improvement</h3>
                    <p class="muted">Launch a fresh practice attempt directly from the current revision set.</p>
                </div>
            </div>
            <div class="revision-quick-grid">
                <article class="mini-stat"><span class="label">Visible in review</span><strong>${queue.length}</strong><small>Questions match the currently active review filters.</small></article>
                <article class="mini-stat"><span class="label">Incorrect</span><strong>${incorrectCount}</strong><small>Questions answered wrong in the current revision set.</small></article>
                <article class="mini-stat"><span class="label">Must revise</span><strong>${revisionPriorityCount}</strong><small>Questions carrying the Must Revise tag.</small></article>
                <article class="mini-stat"><span class="label">Question bank</span><strong>${reviewTest.questions.length}</strong><small>Total questions available in this revision selection.</small></article>
            </div>
            <div class="stacked-chips revision-action-row">
                <button class="primary-btn small" type="button" data-review-practice="filtered">Re-practice current filter set</button>
                <button class="ghost-btn small" type="button" data-review-practice="incorrect">Re-practice incorrect only</button>
                <button class="ghost-btn small" type="button" data-review-practice="learningTags">Re-practice learning tags</button>
                <button class="ghost-btn small" type="button" data-review-practice="shuffle">Shuffle full set</button>
                <button class="ghost-btn small" type="button" id="openReviewDownloadBtn">Download review pack</button>
            </div>
        </section>
        <section class="panel">
            <div class="section-head"><div><p class="eyebrow">Review Filters</p><h3>${selected.label}</h3><p class="muted">Go straight to incorrect or learning-tagged questions for this revision selection.</p></div></div>
            <div class="review-filter-groups">
                ${filterGroups.map((group) => `
                    <div class="review-filter-layer">
                        <span class="label">${group.title}</span>
                        <div class="stacked-chips">${group.items.map(([value, label]) => `<button type="button" class="chip ${state.reviewFilters.includes(value) ? "active-chip" : ""}" data-review-filter="${value}">${label}</button>`).join("")}</div>
                    </div>
                `).join("")}
            </div>
        </section>
        <section class="review-grid">
            ${queue.map((question) => {
                const hydratedReviewQ = hydrateQuestionRecord(question, reviewTest);
                const explanationView = explanationRenderQuestion(hydratedReviewQ);
                const reviewQuestionTestKey = question.__attemptTestId || (reviewTest.id !== "review-scope-topic" ? reviewTest.id : "");
                const safeReviewTags = Array.isArray(question.reviewTags) ? question.reviewTags : [];
                const folderTagOptions = [...new Set([...(state.userTags || []), ...(state.userCustomTags || [])])];
                return `
                <article class="review-card" data-review-question-test-id="${escapeHtml(String(reviewQuestionTestKey || ""))}">
                    <div class="review-head">
                        <span class="label">Q${question.questionNumber}</span>
                        <button class="ghost-btn small" type="button" data-reset-question="${question.id}" data-attempt-test="${question.__attemptTestId || reviewTest.id}">Reset history</button>
                    </div>
                    <div class="question-text-block compact-question"><h3>Q${question.questionNumber}.</h3><div>${renderQuestionContent(question)}</div></div>
                    ${question.__attemptTitle ? `<p class="muted"><strong>From:</strong> ${question.__attemptTitle} • ${question.__attemptProvider || question.source?.sourceText || ""}</p>` : ""}
                    <p class="muted"><strong>Your answer:</strong> ${question.selectedAnswer || "Unattempted"} • <strong>Correct:</strong> ${question.correctAnswer}</p>
                    <div class="review-options">
                        ${orderedOptions(question.options || {}).map(([key, value]) => {
                            const isCorrect = question.correctAnswer === key;
                            const isSelected = question.selectedAnswer === key;
                            const optionState = isCorrect && isSelected ? "review-option correct selected" : isCorrect ? "review-option correct" : isSelected ? "review-option incorrect selected" : "review-option";
                            const optionLabel = isCorrect && isSelected ? '<span class="review-badge success">Your correct answer</span>' : isCorrect ? '<span class="review-badge success">Correct answer</span>' : isSelected ? '<span class="review-badge danger">Your answer</span>' : "";
                            return `<div class="${optionState}"><div class="review-option-main"><strong>${key})</strong><span>${value}</span></div>${optionLabel}</div>`;
                        }).join("")}
                    </div>
                        <div class="review-tag-cluster">
                            <div class="stacked-chips compact-review-tags">${allLearningTags().map((tag) => {
                                const active = safeReviewTags.includes(tag);
                                return `<button type="button" class="chip ${active ? "active-chip" : ""}" data-review-tag="${tag}" data-question-id="${question.id}" data-attempt-test="${question.__attemptTestId || reviewTest.id}">${tag}</button>`;
                            }).join("")}</div>
                            ${folderTagOptions.length ? `<div class="review-folder-row"><select data-review-folder="${question.id}"><option value="">Add Tag</option>${folderTagOptions.map((tag) => `<option value="${tag}">${tag}</option>`).join("")}</select><button class="ghost-btn small" type="button" data-review-folder-save="${question.id}" data-attempt-test="${question.__attemptTestId || reviewTest.id}">Save Tag</button></div>` : ""}
                            ${(question.reviewTags || []).filter((t) => folderTagOptions.includes(t)).length ? `<div class="stacked-chips compact-review-tags">${question.reviewTags.filter((t) => folderTagOptions.includes(t)).map((tag) => `<span class="chip active-chip">${tag}</span>`).join("")}</div>` : ""}
                        </div>
                    <div class="details-block">
                        ${renderExplanationSourceSwitcher(explanationView)}
                        <p><strong>Explanation</strong></p>
                        <div>${renderSimpleMarkdown(getExplanationMarkdown(explanationView) || "No explanation available.")}</div>
                        ${(() => {
                            const m = explanationView.mergedExplanations;
                            const ex = explanationView.explanations;
                            const stack = (Array.isArray(m) && m.length >= 2) ? m
                                : (Array.isArray(ex) && ex.length >= 2
                                    ? ex.map((entry) => ({
                                        provider: entry.source || "Unknown",
                                        markdown: entry.markdown || "",
                                        length: String(entry.markdown || "").length
                                    }))
                                    : []);
                            if (stack.length < 2) return "";
                            return `<div class="merged-explanations-stack" style="margin-top: 16px;"><p class="eyebrow" style="margin-bottom: 8px;">All source explanations</p>
                                ${stack.map((e) => `
                                    <details style="margin-bottom: 8px; border: 1px solid var(--line); border-radius: 8px;">
                                        <summary style="padding: 10px; cursor: pointer; font-weight: 600;">${escapeHtml(e.provider)}</summary>
                                        <div style="padding: 12px;">${renderSimpleMarkdown(e.markdown)}</div>
                                    </details>`).join("")}
                            </div>`;
                        })()}
                        ${renderAlsoAppearsIn(hydratedReviewQ)}
                        <label class="note-layer"><span class="label">Personal note</span><textarea rows="2" data-review-note="${question.id}" placeholder="Short memory aid or reminder">${escapeHtml(Object.prototype.hasOwnProperty.call(state.reviewNoteDrafts, question.id) ? state.reviewNoteDrafts[question.id] : (question.note || ""))}</textarea></label><div class="stacked-chips compact-review-tags"><button class="ghost-btn small" type="button" data-review-save-extras="${question.id}" data-attempt-test="${question.__attemptTestId || reviewTest.id}">Save note</button></div>${question.note ? `<p><strong>Personal note:</strong> ${escapeHtml(question.note)}</p>` : ""}<p class="muted" style="font-size: 0.85rem;">${question.source?.sourceText || ""}${question.microTopic ? ` • ${question.microTopic}` : ""}</p></div>
                </article>
            `;
            }).join("")}
        </section>
        ${buildReviewQueue(attempt, state.reviewFilters).length > 20 ? `<section class="panel"><p class="muted">Showing first 20 questions in this review set to keep the page fast.</p></section>` : ""}
    `;
}

function startPracticeWithPool(mode) {
    const test = activeTest();
    const questionPool = buildPracticeQuestions(mode);
    state.activeAttempt = createAttemptDraft(
        {
            ...test,
            title: resolveAttemptTitle([
                testPrimarySubjectValue(test) || "",
                mode === "fullTest" ? test.title : `${test.title} Custom Practice`
            ]),
            questions: questionPool
        },
        {
            explanationMode: "ask",
            timerMode: "ask",
            timerMinutes: Number(state.customQuestionCount) > 0 ? test.defaultMinutes : test.defaultMinutes
        }
    );
    startTimerIfNeeded();
    state.submitConfirmOpen = false;
    state.paletteOpen = false;
    state.currentView = "practice";
    renderApp();
}

function startReviewRepractice(kind) {
    const ctx = buildCurrentReviewContext();
    if (!ctx?.attempt?.questions?.length || !ctx.test) {
        setAuthNotice("Open a review set first.", "info");
        return;
    }
    const attempt = ctx.attempt;
    const reviewTest = ctx.test;
    const filteredPool = attempt.questions.filter(questionMatchesSourceFilters);
    let pool;
    if (kind === "incorrect") {
        pool = buildReviewQueue({ ...attempt, questions: filteredPool }, ["incorrect"]);
    } else if (kind === "learningTags") {
        pool = filteredPool.filter((q) => (q.reviewTags || []).length > 0);
    } else if (kind === "shuffle") {
        pool = shuffleArray([...filteredPool]);
    } else {
        pool = buildReviewQueue({ ...attempt, questions: filteredPool }, state.reviewFilters);
    }
    if (!pool.length) {
        setAuthNotice("No questions match this practice action.", "info");
        return;
    }
    const minutes = Number(reviewTest.defaultMinutes) > 0 ? Number(reviewTest.defaultMinutes) : 60;
    state.activeAttempt = createAttemptDraft(
        {
            ...reviewTest,
            title: `${reviewTest.title} • Review practice`,
            questions: pool.map((q) => resolveQuestion({ ...q }))
        },
        {
            explanationMode: "ask",
            timerMode: "ask",
            timerMinutes: minutes
        }
    );
    startTimerIfNeeded();
    state.submitConfirmOpen = false;
    state.paletteOpen = false;
    state.currentView = "practice";
    renderApp();
}

function startPracticeBySyllabus() {
    let questionPool = buildSyllabusPracticeQuestions();
    if (state.customShuffle) questionPool = shuffleArray(questionPool);
    const manualQuestionCount = Number.parseInt(state.practiceManualQuestionCount, 10);
    if (Number.isFinite(manualQuestionCount) && manualQuestionCount > 0) {
        questionPool = questionPool.slice(0, manualQuestionCount);
    } else if (state.practiceQuestionMode === "50") {
        questionPool = questionPool.slice(0, 50);
    } else if (state.practiceQuestionMode === "100") {
        questionPool = questionPool.slice(0, 100);
    }

    if (!questionPool.length) {
        setAuthNotice("No questions are available for that syllabus selection yet. Try another subject or micro topic.", "warning");
        renderApp();
        return;
    }

    const titleParts = [state.practiceTopicSubject];
    if (state.practiceTopicSectionGroup && state.practiceTopicSectionGroup !== "All") titleParts.push(state.practiceTopicSectionGroup);
    if (state.practiceTopicMicroTopic && state.practiceTopicMicroTopic !== "All") titleParts.push(state.practiceTopicMicroTopic);

    state.activeAttempt = createAttemptDraft(
        {
            ...activeTest(),
            id: `syllabus-${Date.now()}`,
            title: resolveAttemptTitle([state.practiceTopicSubject, titleParts.filter(Boolean).join(" "), "Topic Practice"]),
            provider: "Mixed Sources",
            subject: state.practiceTopicSubject,
            sectionGroup: state.practiceTopicSectionGroup === "All" ? null : state.practiceTopicSectionGroup,
            questions: questionPool
        },
        {
            explanationMode: "ask",
            timerMode: "ask",
            timerMinutes: activeTest().defaultMinutes
        }
    );
    clearAuthNotice();
    startTimerIfNeeded();
    state.submitConfirmOpen = false;
    state.paletteOpen = false;
    state.currentView = "practice";
    persistActiveAttemptDraft();
    renderApp();
}

