function refocusPracticeSearchInput(cursorPosition = null) {
    requestAnimationFrame(() => {
        const input = document.getElementById("practiceSearchInput");
        if (!input) return;
        input.focus();
        const nextCursor = typeof cursorPosition === "number" ? cursorPosition : input.value.length;
        try {
            input.setSelectionRange(nextCursor, nextCursor);
        } catch {
            // ignore cursor restore issues
        }
    });
}

function bindPracticeSearchResultEvents() {
    document.querySelectorAll("[data-search-test-pick]").forEach((button) => button.addEventListener("click", () => {
        applySearchTestPick(button.dataset.searchTestPick);
    }));
    document.getElementById("launchSearchStartBtn")?.addEventListener("click", async () => {
        const liveValue = document.getElementById("practiceSearchInput")?.value || state.practiceSearchDraft;
        applyPracticeSearchQuery(liveValue);
        invalidatePracticeSearchCache();
        if (state.currentView === "study") {
            launchStudySession(
                async () => startStudyBySearch(),
                "No matching questions found for that search. Try another keyword."
            );
            return;
        }
        startPracticeBySearch();
    });
    
    // Bind "Normal Study Mode" button - moved here because it needs to rebind when search results update
    document.getElementById("launchSearchStudyBtn")?.addEventListener("click", async () => {
        const liveValue = document.getElementById("practiceSearchInput")?.value || state.practiceSearchDraft;
        applyPracticeSearchQuery(liveValue);
        // Force refresh of search results by clearing cache
        practiceSearchCacheKey = null;
        practiceSearchCacheResults = [];
        launchStudySession(
            async () => {
                return startStudyBySearch();
            },
            "No matching questions found for that search. Try another keyword."
        );
    });
    
    // Bind "Textbook-Themed Study Mode" button - moved here because it needs to rebind when search results update
    document.getElementById("launchSearchReadBtn")?.addEventListener("click", async () => {
        const liveValue = document.getElementById("practiceSearchInput")?.value || state.practiceSearchDraft;
        applyPracticeSearchQuery(liveValue);
        // Force refresh of search results by clearing cache
        practiceSearchCacheKey = null;
        practiceSearchCacheResults = [];
        launchStudySession(
            async () => {
                return startStudyBySearch();
            },
            "No matching questions found for that search. Try another keyword.",
            true // Open in read mode
        );
    });
}

function syncPracticeSearchUi() {
    if (shouldUseServerQuestionSearch() && !state.practiceSearchServerLoading) {
        scheduleServerQuestionSearch();
    }
    const results = document.getElementById("practiceSearchResults");
    if (results) {
        teardownPracticeSearchVirtualList();
        results.innerHTML = renderPracticeSearchResultsLimited();
        bindPracticeSearchResultEvents();
        queueMicrotask(() => hydratePracticeSearchVirtualList());
    }
    const clearButton = document.getElementById("practiceSearchClearBtn");
    if (clearButton) {
        clearButton.classList.toggle("is-hidden", !state.practiceSearchDraft);
    }
    // Update button states based on search results
    const hasResults = matchingQuestionsBySearch().length > 0;
    const studyBtn = document.getElementById("launchSearchStudyBtn");
    const readBtn = document.getElementById("launchSearchReadBtn");
    const startBtn = document.getElementById("launchSearchStartBtn");
    if (studyBtn) studyBtn.disabled = !hasResults || state.studyLaunchBusy;
    if (readBtn) readBtn.disabled = !hasResults;
    if (startBtn) startBtn.disabled = !hasResults;
}

async function persistUserSettingsPatch(patch) {
    if (!state.currentUser) return;
    await saveUserSettings(state.currentUser.uid, {
        accountEmail: state.currentUser.email || "",
        accountUid: state.currentUser.uid,
        ...patch
    });
}

function startReviewPractice(mode) {
    const selected = buildCurrentReviewContext();
    const attempt = selected?.attempt;
    const reviewTest = selected?.test;
    if (!attempt?.submittedAt || !reviewTest) return;

    let questionPool = [...attempt.questions];
    if (mode === "filtered") {
        const visibleIds = new Set(buildReviewQueue(attempt, state.reviewFilters).map((question) => question.id));
        questionPool = questionPool.filter((question) => visibleIds.has(question.id));
    }
    if (mode === "incorrect") {
        const wrongIds = new Set(
            attempt.questions
                .filter((question) => question.selectedAnswer && question.selectedAnswer !== question.correctAnswer)
                .map((question) => question.id)
        );
        questionPool = questionPool.filter((question) => wrongIds.has(question.id));
    }
    if (mode === "mustRevise") {
        const reviseIds = new Set(
            attempt.questions
                .filter((question) => question.reviewTags?.includes("Must Revise"))
                .map((question) => question.id)
        );
        questionPool = questionPool.filter((question) => reviseIds.has(question.id));
    }
    if (mode === "learningTags") {
        const learningTagIds = new Set(
            attempt.questions
                .filter((question) => question.reviewTags && question.reviewTags.length > 0)
                .map((question) => question.id)
        );
        questionPool = questionPool.filter((question) => learningTagIds.has(question.id));
    }
    if (mode === "shuffle") {
        questionPool = shuffleArray(questionPool);
    }

    if (!questionPool.length) {
        setAuthNotice("No questions match that revision action yet. Try another filter or tag more questions first.", "warning");
        renderApp();
        return;
    }

    state.selectedTestId = selected.selectedTestId || state.selectedTestId || activeTest()?.id || null;
    state.activeAttempt = createAttemptDraft(
        {
            ...reviewTest,
            title: `${reviewTest.title} • Revision Practice`,
            questions: questionPool
        },
        {
            explanationMode: "afterSubmit",
            timerMode: "untimed",
            timerMinutes: reviewTest.defaultMinutes
        }
    );
    clearAuthNotice();
    startTimerIfNeeded();
    state.submitConfirmOpen = false;
    state.paletteOpen = false;
    state.currentView = "practice";
    persistActiveAttemptDraft();
    renderApp();
}

function describeAttemptQuality(score, confidenceInsights, decisionMetrics) {
    const strongestDecision = [...decisionMetrics].sort((a, b) => b.accuracy - a.accuracy)[0];
    const weakestDecision = [...decisionMetrics].sort((a, b) => a.accuracy - b.accuracy)[0];
    const notes = [
        `Your current Attempt Quality Score is ${score.attemptQualityScore}, which reads as ${score.qualityLabel.toLowerCase()}.`,
        strongestDecision?.total ? `${strongestDecision.label} is currently your best-calibrated decision pattern.` : "Decision calibration is still too thin to call one pattern reliable.",
        confidenceInsights.sureWrong > 0
            ? `${confidenceInsights.sureWrong} high-confidence mistakes suggest your self-evaluation still needs tightening.`
            : "High-confidence choices are staying relatively clean in this attempt.",
        weakestDecision?.total ? `${weakestDecision.label} is the least reliable pattern right now, so that is the first place to adjust.` : ""
    ].filter(Boolean);
    return notes.join(" ");
}

function renderRunner(test, attempt) {
    const pages = chunkQuestions(attempt.questions, 6);
    const currentPage = Math.floor(attempt.currentIndex / 6);
    const pageQuestions = pages[currentPage] || [];
    const answeredCount = attempt.questions.filter((question) => question.selectedAnswer).length;
    const reviewCount = attempt.questions.filter((question) => question.markForReview).length;
    return `
        <section class="paper-shell">
            <div class="paper-topbar">
                <div>
                    <p class="eyebrow">Attempt paper</p>
                    <h3>${test.title}</h3>
                    <p class="muted">Page ${currentPage + 1} of ${pages.length} • ${answeredCount} answered • ${reviewCount} review</p>
                </div>
                <div class="paper-actions">
                    <div class="timer-pill">${attempt.timerMode === "timed" ? `Time left ${formatRemaining(state.timeRemainingMs)}` : "Untimed / Ask"}</div>
                    <button class="primary-btn" type="button" id="submitAttemptBtn">Submit test</button>
                </div>
            </div>
            <div class="paper-layout">
                <div class="a4-paper">
                    <div class="paper-grid">
                        ${pageQuestions.map((q) => {
                            const index = attempt.questions.findIndex((item) => item.id === q.id);
                            return `<article class="paper-question ${attempt.currentIndex === index ? "focus-question" : ""}">
                                <div class="paper-question-head">
                                    <div class="question-meta"><span class="chip">Q${q.questionNumber}</span>${renderQuestionCornerMeta(q)}</div>
                                    <button type="button" class="ghost-btn small" data-toggle-review="${index}">${q.markForReview ? "Review marked" : "Mark review"}</button>
                                </div>
                                <div class="question-text-block compact-question">${renderQuestionContent(q)}</div>
                                <div class="option-list compact-options">${orderedOptions(q.options).map(([key, value]) => `<label class="option-row ${q.selectedAnswer === key ? "selected" : ""}"><input type="radio" name="answerOption-${index}" value="${key}" data-qindex="${index}" ${q.selectedAnswer === key ? "checked" : ""}><span><strong>${key})</strong> ${value}</span></label>`).join("")}</div>
                                <div class="review-tag-layer"><span class="label">Confidence</span><div class="stacked-chips">${appConfig.confidenceTags.map((tag) => `<button type="button" class="chip ${q.confidence === tag ? "active-chip" : ""}" data-confidence="${tag}" data-qindex="${index}">${tag}</button>`).join("")}</div></div>
                                <label class="note-layer"><span class="label">Quick note</span><textarea rows="2" data-note-index="${index}" placeholder="Trap / memory aid">${q.note || ""}</textarea></label>
                            </article>`;
                        }).join("")}
                    </div>
                    <div class="practice-footer"><button class="ghost-btn" type="button" id="prevPageBtn" ${currentPage === 0 ? "disabled" : ""}>Previous page</button><button class="primary-btn" type="button" id="reviewSaveTagsBtn" title="Save all tags and folders for current page">Save Tags</button><button class="primary-btn" type="button" id="reviewSaveFoldersBtn" title="Save all folders for current page to database">Save Folders</button><button class="ghost-btn" type="button" id="nextPageBtn" ${currentPage === pages.length - 1 ? "disabled" : ""}>Next page</button></div>
                </div>
                <aside class="palette-panel">
                    <div class="palette-head"><p class="eyebrow">Question Palette</p><p class="muted">Answered / Unanswered / Review</p></div>
                    <div class="palette-grid">
                        ${attempt.questions.map((question, index) => {
                            const statusClass = question.markForReview ? "review" : question.selectedAnswer ? "answered" : "unanswered";
                            return `<button type="button" class="palette-btn ${statusClass} ${attempt.currentIndex === index ? "current" : ""}" data-palette-index="${index}">${question.questionNumber}</button>`;
                        }).join("")}
                    </div>
                    <div class="palette-legend">
                        <span><i class="legend-box answered"></i> Answered</span>
                        <span><i class="legend-box unanswered"></i> Unanswered</span>
                        <span><i class="legend-box review"></i> Review</span>
                    </div>
                </aside>
            </div>
        </section>
    `;
}

function renderReview(attempt) {
    if (!attempt?.submittedAt) return `<section class="panel empty-panel"><p class="eyebrow">Review</p><h3>No submitted attempt yet</h3><p class="muted">Submit a test to unlock tagging and difficulty review.</p></section>`;
    const queue = buildReviewQueue(attempt, state.reviewFilters);
    return `
        <section class="panel">
            <div class="section-head"><div><p class="eyebrow">Review Filters</p><h3>Question-wise review</h3><p class="muted">Go straight to incorrect or revision-marked questions.</p></div></div>
            <div class="stacked-chips">
                ${[
                    ["incorrect", "Incorrect only"],
                    ["all", "All attempted"],
                    ["tough", "Tough"],
                    ["mustRevise", "Must Revise"],
                    ["pyq", "PYQ"],
                    ["conceptual", "Conceptual"],
                    ["factual", "Factual"],
                    ["silly", "Silly"],
                    ["guessed", "Guessed"],
                    ["eliminated", "Eliminated"],
                    ["sure", "100% Sure"],
                    ["logical", "Logical"],
                    ["guess", "Pure Guess"],
                    ["funda", "UPSC Funda"],
                    ["easy", "Easy"],
                    ["moderate", "Moderate"],
                    ["hard", "Hard"]
                ].map(([value, label]) => `<button type="button" class="chip ${state.reviewFilters.includes(value) ? "active-chip" : ""}" data-review-filter="${value}">${label}</button>`).join("")}
            </div>
        </section>
        <section class="review-grid">
            ${queue.map((question) => `<article class="review-card" data-question-id="${question.id}" data-test-id="${question.testId || state.activeTestId}"><div class="review-head"><span class="label">Q${question.questionNumber}</span><button class="ghost-btn small" type="button" data-reset-question="${question.id}">Reset history</button></div><div class="question-text-block compact-question"><h3>Q${question.questionNumber}.</h3><div>${renderQuestionContent(question)}</div></div><p class="muted"><strong>Your answer:</strong> ${question.selectedAnswer || "Unattempted"} • <strong>Correct:</strong> ${question.correctAnswer}</p><div class="stacked-chips">${allLearningTags().map((tag) => `<button type="button" class="chip ${(question.reviewTags || []).includes(tag) ? "active-chip" : ""}" data-review-tag="${tag}" data-question-id="${question.id}">${tag}</button>`).join("")}</div><div class="stacked-chips">${["Easy", "Moderate", "Hard"].map((level) => `<button type="button" class="chip ${question.reviewDifficulty === level ? "active-chip" : ""}" data-difficulty="${level}" data-question-id="${question.id}">${level}</button>`).join("")}</div><div class="details-block"><p><strong>Explanation</strong></p><div>${renderSimpleMarkdown(question.explanationMarkdown)}</div><p class="muted"><strong>Source:</strong> ${question.source.sourceText}</p><p class="muted"><strong>Topic:</strong> ${question.microTopic}</p></div></article>`).join("")}
        </section>
    `;
}

function renderTable(headers, rows) {
    return `
        <div class="analytics-table-wrap">
            <table class="analytics-table">
                <thead>
                    <tr>${headers.map((header) => `<th>${header}</th>`).join("")}</tr>
                </thead>
                <tbody>${rows || `<tr><td colspan="${headers.length}">No data yet</td></tr>`}</tbody>
            </table>
        </div>
    `;
}

function taxonomySubjects() {
    return [...new Set(prelimsTaxonomy.map((item) => item.subject).filter(Boolean))];
}

function taxonomySectionGroups(subject) {
    return [...new Set(prelimsTaxonomy.filter((item) => item.subject === subject).map((item) => item.sectionGroup).filter(Boolean))];
}

function taxonomyMicroTopics(subject, sectionGroup) {
    return prelimsTaxonomy
        .filter((item) => item.subject === subject && ((sectionGroup ?? null) === (item.sectionGroup ?? null)))
        .map((item) => item.microTopic);
}

function sourceExamOptions() {
    return ["None", "UPSC CSE Prelims", "UPSC CDS I", "UPSC CDS II", "UPSC CAPF"];
}

function sourceYearOptions() {
    const currentYear = new Date().getFullYear();
    return Array.from({ length: currentYear - 1994 }, (_, index) => String(currentYear - index));
}

function buildAdminSourceText() {
    const exam = document.getElementById("adminSourceExam")?.value || "None";
    const year = document.getElementById("adminSourceYear")?.value || "";
    if (exam === "None") return "";
    return year ? `${exam} ${year}` : exam;
}

function allSubmittedQuestions() {
    return submittedAttempts().flatMap(({ attempt }) => attempt.questions || []);
}

function buildDailyTargetTracker() {
    const today = new Date().toLocaleDateString("en-CA");
    const todayAttempts = submittedAttempts().filter(({ attempt }) => (attempt.submittedAt || "").slice(0, 10) === today);
    const todayQuestions = todayAttempts.flatMap(({ attempt }) => attempt.questions || []);
    const revisedToday = todayQuestions.filter((question) => Array.isArray(question.reviewTags) && question.reviewTags.length).length;
    const topicCount = new Set(todayQuestions.map((question) => question.microTopic).filter(Boolean)).size;
    return {
        attempts: todayAttempts.length,
        questionsSolved: todayQuestions.filter((question) => question.selectedAnswer).length,
        topicsTouched: topicCount,
        revisedTagged: revisedToday
    };
}

function normalizeDuplicateStem(question) {
    return normalizedSearch([
        question.questionText,
        ...(question.statementLines || [])
    ]).replace(/\s+/g, " ").trim();
}

function adminBulkQuestionPool() {
    const baseTests = state.selectedTestId === "__all__"
        ? adminVisibleTests()
        : adminVisibleTests().filter((test) => test.id === state.selectedTestId);
    return baseTests.flatMap((test) => (test.questions || []).map((question) => ({
        ...question,
        __bulkTestId: test.id,
        __bulkTestTitle: test.title,
        __bulkSubject: questionSubjectValue(question, test),
            __bulkSectionGroup: questionSectionGroupValue(question, test)
        })));
}

function adminVisibleQuestionTotal() {
    return sumQuestionTotals(adminVisibleTests());
}

function adminInspectionQuestionTotal() {
    return sumQuestionTotals(adminInspectionBaseTests());
}

function sourceCleanupDisplayLabel(question = {}) {
    return pyqBadgeLabel(question) || String(question.source?.sourceText || "").trim() || "No source";
}

function sourceCleanupOptions() {
    const labels = new Set();
    sampleTests.forEach((test) => {
        (test.questions || []).forEach((question) => {
            labels.add(sourceCleanupDisplayLabel(question));
        });
    });
    return [...labels].filter(Boolean).sort((left, right) => left.localeCompare(right));
}

function adminSourceCleanupPool() {
    const filterValue = normalizedSearch(state.adminSourceCleanupFilter);
    return adminBulkQuestionPool().filter((question) => {
        if (!filterValue) return true;
        const display = sourceCleanupDisplayLabel(question);
        const rawSource = String(question.source?.sourceText || "");
        return normalizedSearch(display).includes(filterValue) || normalizedSearch(rawSource).includes(filterValue);
    });
}

function adminValidationReport() {
    return sampleTests.flatMap((test) => (test.questions || []).flatMap((question) => {
        const issues = [];
        if (!question.microTopic) issues.push("Missing micro-topic");
        if (!question.explanationMarkdown) issues.push("Missing explanation");
        if (orderedOptions(question.options || {}).length < 4) issues.push("Incomplete options");
        if (!["a", "b", "c", "d", "e", "f"].includes(String(question.correctAnswer || "").toLowerCase())) issues.push("Invalid correct answer");
        if ((question.statementLines || []).some((line) => /\t|\|/.test(line))) issues.push("Possible table/text flattening issue");
        return issues.length ? [{
            testId: test.id,
            questionId: question.id,
            title: test.title,
            questionNumber: question.questionNumber,
            issues: issues.join(", ")
        }] : [];
    }));
}

function adminSelectionToolbar(label = "selected questions") {
    if (!state.adminBulkSelectionIds.length) return "";
    return `
        <div class="review-head compact-review-head">
            <span class="label">${state.adminBulkSelectionIds.length} ${label}</span>
            <button class="ghost-btn small" type="button" data-admin-open-bulk-editor>Open selected in bulk editor</button>
        </div>
    `;
}

function adminDuplicateReport() {
    const bucket = new Map();
    sampleTests.forEach((test) => {
        (test.questions || []).forEach((question) => {
            const stem = normalizeDuplicateStem(question);
            if (!stem || stem.length < 25) return;
            const current = bucket.get(stem) || [];
            current.push({
                testId: test.id,
                questionId: question.id,
                title: test.title,
                questionNumber: question.questionNumber,
                microTopic: question.microTopic || "-",
                provider: test.provider || "Unknown",
                correctAnswer: question.correctAnswer || "N/A"
            });
            bucket.set(stem, current);
        });
    });
    return [...bucket.entries()]
        .filter(([, items]) => items.length > 1)
        .slice(0, 40)
        .map(([stem, items]) => ({ stem, items }));
}

function findDuplicateQuestions(questionText, options, correctAnswer) {
    const visibleTests = adminVisibleTests();
    const allQuestions = visibleTests.flatMap((test) => (test.questions || []).map((question) => ({
        ...question,
        __searchTestId: test.id,
        __searchTestTitle: test.title,
        __searchProvider: testInstituteValue(test),
        __searchSubject: questionSubjectValue(question, test)
    })));
    
    const targetStem = normalizeDuplicateStem({ questionText });
    
    return allQuestions.filter(question => {
        const questionStem = normalizeDuplicateStem(question);
        // Simple similarity check - can be enhanced with more sophisticated algorithms
        return questionStem === targetStem ||
               questionStem.includes(targetStem) ||
               targetStem.includes(questionStem);
    });
}

function displayDuplicateResults(duplicates, officialQuestion) {
    const resultsDiv = document.getElementById("duplicateDetectionResults");
    const matchesListDiv = document.getElementById("duplicateMatchesList");
    
    if (duplicates.length === 0) {
        matchesListDiv.innerHTML = '<p class="muted">No duplicates found for this official question.</p>';
    } else {
        matchesListDiv.innerHTML = `
            <div class="duplicate-matches">
                ${duplicates.map(question => `
                    <div class="duplicate-match-item" style="border: 1px solid var(--line); border-radius: 8px; padding: 12px; margin-bottom: 12px;">
                        <div style="display: flex; justify-content: space-between; align-items: start;">
                            <div style="flex: 1;">
                                <strong>${question.title || 'Unknown Test'} - Q${question.questionNumber || 'N/A'}</strong>
                                <div style="color: var(--muted); font-size: 0.9rem; margin-top: 4px;">
                                    Provider: ${question.provider || 'Unknown'} | 
                                    Subject: ${question.subject || 'Unknown'} |
                                    Answer: ${question.correctAnswer || 'N/A'}
                                </div>
                                <div style="margin-top: 8px;">
                                    <strong>Question:</strong> ${escapeHtml(question.questionText || '').slice(0, 200)}...
                                </div>
                                ${question.correctAnswer !== officialQuestion.correctAnswer.toUpperCase() ? 
                                    `<div style="color: #dc3545; margin-top: 4px; font-weight: 600;">
                                        <strong>Answer Conflict:</strong> Official: ${officialQuestion.correctAnswer.toUpperCase()}, Coaching: ${question.correctAnswer}
                                    </div>` : ''}
                            </div>
                            <div class="stacked-chips" style="margin-left: 12px;">
                                <button class="ghost-btn tiny" type="button" data-link-to-official="${question.id}">Link to Official</button>
                                <button class="ghost-btn tiny" type="button" data-set-as-official="${question.id}">Use as Official</button>
                            </div>
                        </div>
                    </div>
                `).join('')}
            </div>
        `;
        
        // Add event listeners for the new buttons
        matchesListDiv.querySelectorAll("[data-link-to-official]").forEach(button => {
            button.addEventListener("click", () => {
                const questionId = button.dataset.linkToOfficial;
                linkQuestionToOfficial(questionId, officialQuestion);
            });
        });
        
        matchesListDiv.querySelectorAll("[data-set-as-official]").forEach(button => {
            button.addEventListener("click", () => {
                const questionId = button.dataset.setAsOfficial;
                setQuestionAsOfficial(questionId, officialQuestion);
            });
        });
    }
    
    resultsDiv.style.display = "block";
}

