function escapeHtml(value = "") {
    return String(value)
        .replace(/&/g, "&amp;")
        .replace(/</g, "&lt;")
        .replace(/>/g, "&gt;")
        .replace(/"/g, "&quot;")
        .replace(/'/g, "&#39;");
}

function buildIncorrectQuestionsDocument(attemptRecord, options = {}) {
    const selected = attemptRecord?.attempt || attemptRecord?.selected || attemptRecord;
    const test = attemptRecord?.test || attemptRecord?.reviewTest || attemptRecord?.testRecord || null;
    const fontSize = options.fontSize || "1rem";
    const exportLabel = options.label || "Incorrect Questions";
    const includeExplanations = options.includeExplanations !== false;
    const incorrectQuestions = selected?.questions?.filter((question) =>
        typeof options.filter === "function"
            ? options.filter(question)
            : question.selectedAnswer && question.selectedAnswer !== question.correctAnswer
    ) || [];

    const title = `${test?.title || "Dr. UPSC Practice"} - ${exportLabel}`;
    const body = incorrectQuestions.length
        ? (() => {
            // Group questions by subject, then by tag within each subject
            const questionsBySubject = {};
            incorrectQuestions.forEach(question => {
                const subject = question.subject || "Uncategorized";
                if (!questionsBySubject[subject]) {
                    questionsBySubject[subject] = {};
                }
                
                // Group by tags within each subject
                const tags = question.reviewTags || [];
                if (tags.length === 0) {
                    if (!questionsBySubject[subject]["__untagged__"]) {
                        questionsBySubject[subject]["__untagged__"] = [];
                    }
                    questionsBySubject[subject]["__untagged__"].push(question);
                } else {
                    tags.forEach(tag => {
                        if (!questionsBySubject[subject][tag]) {
                            questionsBySubject[subject][tag] = [];
                        }
                        questionsBySubject[subject][tag].push(question);
                    });
                }
            });
            
            // Generate HTML for true 2-column layout
            let html = "";
            let questionIndex = 1;
            
            // Collect all questions with their subject/tag info
            const allQuestions = [];
            Object.entries(questionsBySubject).forEach(([subject, tagsObj]) => {
                const sortedTags = Object.keys(tagsObj).sort((a, b) => {
                    if (a === "__untagged__") return -1;
                    if (b === "__untagged__") return 1;
                    return a.localeCompare(b);
                });
                
                sortedTags.forEach(tag => {
                    const tagQuestions = tagsObj[tag];
                    const tagLabel = tag === "__untagged__" ? "Uncategorized" : tag;
                    
                    tagQuestions.forEach(question => {
                        allQuestions.push({
                            question,
                            subject,
                            tag: tagLabel,
                            index: questionIndex++
                        });
                    });
                });
            });
            
            // Generate questions in a single flow for proper column layout
            allQuestions.forEach(({ question, subject, tag, index }) => {
                const optionsHtml = orderedOptions(question.options || {}).map(([key, value]) => {
                    return `<li class="download-option"><strong>${escapeHtml(key)})</strong> ${escapeHtml(value)}</li>`;
                }).join("");
                const questionText = question.statementLines?.length
                    ? question.statementLines.map((line) => `<div>${escapeHtml(line)}</div>`).join("")
                    : `<div>${escapeHtml(question.questionText || "")}</div>`;

                const correctOptionText = question.options?.[question.correctAnswer] || "";
                html += `
                    <section class="download-question">
                        <p class="download-index">${index}. Q${escapeHtml(question.questionNumber)}</p>
                        <div class="download-subject-tag">
                            <span class="subject-label" style="color: #2d69c7; font-size: 8pt; font-weight: 600;">${escapeHtml(subject)}</span>
                            <span class="tag-label" style="color: #8a795d; font-size: 8pt; font-weight: 500; margin-left: 4px;">${escapeHtml(tag)}</span>
                        </div>
                        <div class="download-question-text">${questionText}</div>
                        <ol class="download-options" type="a">${optionsHtml}</ol>
                        <div class="download-answer-strip">
                            <span><strong>Your answer:</strong> ${escapeHtml((question.selectedAnswer || "-").toUpperCase())}</span>
                            <span><strong>Correct:</strong> ${escapeHtml((question.correctAnswer || "-").toUpperCase())}${correctOptionText ? ` - ${escapeHtml(correctOptionText)}` : ""}</span>
                        </div>
                        ${question.highlightText ? `<div class="download-explanation"><strong>Saved highlight:</strong> ${escapeHtml(question.highlightText)}</div>` : ""}
                        ${question.note ? `<div class="download-explanation"><strong>Personal note:</strong> ${escapeHtml(question.note)}</div>` : ""}
                        ${!includeExplanations
                            ? ""
                            : options.highlightOnly
                            ? (question.highlightText ? `<div class="download-explanation"><div>${escapeHtml(question.highlightText)}</div></div>` : `<div class="download-explanation muted-print">No saved highlight for this question.</div>`)
                            : `<div class="download-explanation"><div>${renderSimpleMarkdown(question.explanationMarkdown || "No explanation available.")}</div></div>`}
                    </section>
                `;
            });
            
            return html;
        })()
        : `<section class="download-empty"><h3>No matching questions</h3><p>There is nothing to export for this selection right now.</p></section>`;

    return `<!doctype html>
<html lang="en">
<head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <title>${escapeHtml(title)}</title>
    <style>
        @page { size: A4; margin: 10mm 11mm; }
        body { font-family: Georgia, "Times New Roman", serif; color: #111111; margin: 0; line-height: 1.28; font-size: ${fontSize}; background: #ffffff; }
        .sheet { padding: 1mm 1mm 2mm; }
        .title-band { background: #426fc0; color: #ffffff; text-align: center; font: italic 700 11pt Inter, Arial, sans-serif; padding: 1.2mm 2mm; margin-bottom: 2mm; }
        .theme-band { display: inline-block; background: #6d3092; color: #ffffff; font: italic 700 8.4pt Inter, Arial, sans-serif; padding: 0.9mm 3mm; margin-bottom: 2mm; }
        h1 { display: none; }
        .meta { color: #111111; margin: 0 0 2mm; font: 500 8pt Inter, Arial, sans-serif; }
        .download-grid { 
            display: grid; 
            grid-template-columns: repeat(2, minmax(0, 1fr)); 
            gap: 0 6mm; 
            align-items: start; 
            grid-auto-flow: row dense;
        }
        .download-question { 
            border: 0; 
            padding: 0; 
            margin: 0 0 2.6mm; 
            break-inside: avoid; 
            page-break-inside: avoid; 
            min-width: 0;
            orphans: 2;
            widows: 2;
        }
        .download-index { margin: 0 0 1mm; font: 700 8.3pt Inter, Arial, sans-serif; color: #2d69c7; text-decoration: underline; }
        .download-subject-tag { margin: 0 0 1mm; display: flex; align-items: center; gap: 4px; }
        .subject-label { color: #2d69c7; font-size: 8pt; font-weight: 600; }
        .tag-label { 
            color: #ffffff; 
            font-size: 7pt; 
            font-weight: 500; 
            background: #8a795d; 
            padding: 1px 3px; 
            border-radius: 2px;
        }
        .download-question-text { font-size: 9.6pt; margin-bottom: 1mm; }
        .download-question-text div { margin-bottom: 0.8mm; }
        .download-options { margin: 0 0 1mm 14px; padding-left: 0; }
        .download-option { margin: 0 0 0.45mm; color: #111111; }
        .download-answer-strip { display: block; margin-top: 0.8mm; font: 600 8.3pt Inter, Arial, sans-serif; color: #111111; }
        .download-answer-strip span { display: block; margin-bottom: 0.5mm; }
        .download-explanation { margin-top: 1mm; }
        .download-explanation p { margin: 0 0 0.7mm; color: #111111; }
        .download-explanation ul, .download-explanation ol { margin: 0 0 1mm 15px; padding-left: 0; }
        .download-explanation li { margin-bottom: 0.45mm; }
        .muted-print { color: #555; font-style: italic; }
        .download-empty { border: 0; padding: 0; color: #111111; }
        strong { font-weight: 700; }
        mark { background: #1cff3c; padding: 0 1px; }
        @media print {
            .download-grid { 
                display: grid; 
                grid-template-columns: repeat(2, minmax(0, 1fr)); 
                gap: 0 6mm; 
                align-items: start;
                grid-auto-flow: row dense;
            }
            .download-question { 
                break-inside: avoid; 
                page-break-inside: avoid;
                orphans: 2;
                widows: 2;
            }
        }
    </style>
</head>
<body>
    <div class="sheet">
        <div class="title-band">${escapeHtml(test?.title || `${exportLabel} Master File`)}</div>
        <div class="theme-band">${escapeHtml(String(exportLabel).toUpperCase())}${includeExplanations ? " WITH EXPLANATIONS" : " QUESTIONS ONLY"}</div>
        <p class="meta">${escapeHtml(test?.provider || "")}${test?.provider ? " • " : ""}${escapeHtml(test?.subject || "")}${selected?.submittedAt ? ` • Submitted ${new Date(selected.submittedAt).toLocaleString("en-IN")}` : ""}</p>
        <div class="download-grid">${body}</div>
    </div>
</body>
</html>`;
}

function buildIncorrectQuestionsDownload(attemptRecord) {
    return buildIncorrectQuestionsDocument(attemptRecord, { fontSize: "1rem" });
}

function printHtmlInFrame(html) {
    const iframe = document.createElement("iframe");
    iframe.style.position = "fixed";
    iframe.style.right = "0";
    iframe.style.bottom = "0";
    iframe.style.width = "0";
    iframe.style.height = "0";
    iframe.style.border = "0";
    iframe.setAttribute("aria-hidden", "true");
    document.body.appendChild(iframe);
    const frameDoc = iframe.contentWindow?.document;
    if (!frameDoc || !iframe.contentWindow) {
        document.body.removeChild(iframe);
        return;
    }
    let printed = false;
    iframe.onload = () => {
        if (printed) return;
        printed = true;
        iframe.contentWindow.focus();
        iframe.contentWindow.print();
        window.setTimeout(() => {
            if (iframe.parentNode) iframe.parentNode.removeChild(iframe);
        }, 1000);
    };
    frameDoc.open();
    frameDoc.write(html);
    frameDoc.close();
}

function printElementAsPdf(selector, title = "Report") {
    const el = document.querySelector(selector);
    if (!el) {
        showNotice("Nothing to export yet.");
        return;
    }
    const html = `
<!DOCTYPE html>
<html><head><meta charset="UTF-8"><title>${escapeHtml(title)}</title>
<style>
@page { size: A4; margin: 8mm; }
body { font-family: Inter, Arial, sans-serif; margin:0; color:#0f172a; }
.wrap { padding: 8px; }
.title { font-weight: 800; font-size: 18px; margin-bottom: 8px; }
svg, canvas, img { max-width: 100%; page-break-inside: avoid; break-inside: avoid; }
table { width: 100%; border-collapse: collapse; }
button { border: 1px solid #cbd5e1; background: #f8fafc; color: #0f172a; }
</style></head>
<body><div class="wrap"><div class="title">${escapeHtml(title)}</div>${el.outerHTML}</div></body></html>`;
    printHtmlInFrame(html);
}

/** PYQ charts often render to &lt;canvas&gt;; cloning outerHTML drops pixels. Rasterize canvases first. */
function printPyqActiveChartPdf(title = "PYQ Chart") {
    const mount = document.getElementById("pyqGraphInner");
    if (!mount) {
        showNotice("Nothing to export yet.");
        return;
    }
    const canvases = Array.from(mount.querySelectorAll("canvas"));
    const snapshots = canvases
        .map((c) => {
            try {
                return `<div style="margin:10px 0;"><img alt="chart" src="${c.toDataURL("image/png")}" style="max-width:100%;height:auto;border:1px solid #e2e8f0;border-radius:10px;" /></div>`;
            } catch {
                return "";
            }
        })
        .filter(Boolean)
        .join("");
    const fallback = mount.innerHTML || "";
    const body = snapshots || fallback;
    const html = `
<!DOCTYPE html>
<html><head><meta charset="UTF-8"><title>${escapeHtml(title)}</title>
<style>
@page { size: A4; margin: 8mm; }
body { font-family: Inter, Arial, sans-serif; margin:0; color:#0f172a; }
.wrap { padding: 8px; }
.title { font-weight: 800; font-size: 18px; margin-bottom: 8px; }
</style></head>
<body><div class="wrap"><div class="title">${escapeHtml(title)}</div>${body}</div></body></html>`;
    printHtmlInFrame(html);
}

function printPyqMasterChartsPdf() {
    const hasExamSelection = Boolean(state.pyqAnalysisPaper);
    const allPyqs = hasExamSelection ? getAllPyqQuestions() : [];
    const filteredPyqs = hasExamSelection ? filterPyqsByYearRange(allPyqs, state.pyqAnalysisYearStart, state.pyqAnalysisYearEnd) : [];
    if (!filteredPyqs.length) {
        showNotice("No PYQ data available for export.");
        return;
    }

    const years = Array.from({ length: state.pyqAnalysisYearEnd - state.pyqAnalysisYearStart + 1 }, (_, i) => state.pyqAnalysisYearStart + i);
    const subjectGroups = pyqPrimaryGroups(filteredPyqs);
    const yearGroups = groupQuestionsByYear(filteredPyqs);
    const microTopicGroups = groupQuestionsByMicroTopic(filteredPyqs);
    const snapshot = {
        activeGraph: state.pyqAnalysisActiveGraph,
        pieSubject: state.pyqPieSelectedSubject,
        pieSection: state.pyqPieSelectedSection,
        pieFocus: state.pyqPieFocusedSlice
    };

    state.pyqPieSelectedSubject = null;
    state.pyqPieSelectedSection = null;
    state.pyqPieFocusedSlice = null;

    const sections = [
        { title: "Subject Trends", body: renderSubjectTrendGraph(subjectGroups, years, filteredPyqs, subjectGroups) },
        { title: "Subject Distribution", body: renderSubjectDistributionGraph(filteredPyqs, subjectGroups) },
        { title: "Hot Topics", body: renderMicroTopicFrequencyGraph(microTopicGroups) },
        { title: "Subject-Year Heatmap", body: renderSubjectYearHeatmap(subjectGroups, years) },
        { title: "Combined Heatmaps", body: renderCombinedHeatmapsGraph(subjectGroups, filteredPyqs) },
        { title: "Custom Trend Analysis", body: renderFilteredTrendGraph(filteredPyqs, years) }
    ];

    state.pyqAnalysisActiveGraph = snapshot.activeGraph;
    state.pyqPieSelectedSubject = snapshot.pieSubject;
    state.pyqPieSelectedSection = snapshot.pieSection;
    state.pyqPieFocusedSlice = snapshot.pieFocus;

    const html = `
<!DOCTYPE html>
<html><head><meta charset="UTF-8"><title>PYQ Master Report</title>
<style>
@page { size: A4; margin: 8mm; }
body { font-family: Inter, Arial, sans-serif; margin:0; color:#0f172a; background:#ffffff; }
.wrap { padding: 8px; }
.title-band { display:flex; align-items:center; justify-content:center; text-align:center; min-height:16mm; border:1px solid #1f4b99; background: linear-gradient(135deg, #dce8ff 0%, #f5f9ff 100%); color:#12356e; font: 800 16pt "Inter", Arial, sans-serif; letter-spacing:0.02em; border-radius:3mm; }
.meta { margin: 3mm 0 0; text-align:center; color:#475569; font: 500 8.8pt "Inter", Arial, sans-serif; }
.chart-sheet { page-break-before: always; break-before: page; }
.chart-sheet:first-of-type { page-break-before: auto; break-before: auto; }
.chart-title { margin:0 0 10px; font: 800 14pt "Inter", Arial, sans-serif; color:#1e293b; }
.chart-card { border:1px solid #e2e8f0; border-radius:12px; padding:12px; background:#ffffff; }
button { display:none !important; }
select { appearance:none; -webkit-appearance:none; border:1px solid #cbd5e1; background:#f8fafc; }
svg, canvas, img { max-width:100%; height:auto; page-break-inside: avoid; break-inside: avoid; }
</style></head>
<body><div class="wrap">
    <div class="title-band">PYQ Master Report</div>
    <p class="meta">${escapeHtml(state.pyqAnalysisProvider || "UPSC CSE")} • ${escapeHtml(state.pyqAnalysisSection || "-")} • ${escapeHtml(state.pyqAnalysisPaper || "-")} • ${escapeHtml(String(state.pyqAnalysisYearStart))}-${escapeHtml(String(state.pyqAnalysisYearEnd))}</p>
    ${sections.map((section) => `
        <section class="chart-sheet">
            <h2 class="chart-title">${escapeHtml(section.title)}</h2>
            <div class="chart-card">${section.body}</div>
        </section>
    `).join("")}
</div></body></html>`;
    printHtmlInFrame(html);
}

function printPyqSubjectDistributionPdf() {
    const allPyqs = getAllPyqQuestions();
    const filtered = filterPyqsByYearRange(allPyqs, state.pyqAnalysisYearStart, state.pyqAnalysisYearEnd);
    if (!filtered.length) {
        showNotice("No PYQ data available for export.");
        return;
    }
    const subjects = groupQuestionsBySubject(filtered);
    const yearRangeLabel = `${state.pyqAnalysisYearStart} - ${state.pyqAnalysisYearEnd}`;
    const total = filtered.length;
    const subjectCards = Object.entries(subjects)
        .sort((a, b) => b[1].length - a[1].length)
        .map(([subject, qs]) => {
            const pct = total ? ((qs.length / total) * 100).toFixed(1) : "0.0";
            const bySection = groupQuestionsBySection(qs, subject);
            const sectionRows = Object.entries(bySection)
                .sort((a, b) => b[1].length - a[1].length)
                .map(([section, sqs]) => {
                    const secPct = qs.length ? ((sqs.length / qs.length) * 100).toFixed(1) : "0.0";
                    const micro = sqs.reduce((acc, q) => {
                        const key = questionMicroTopicValue(q) || "Uncategorized";
                        acc[key] = (acc[key] || 0) + 1;
                        return acc;
                    }, {});
                    const microRows = Object.entries(micro)
                        .sort((a, b) => b[1] - a[1])
                        .map(([topic, count]) => `<tr><td>${escapeHtml(topic)}</td><td style="text-align:right;">${count}</td></tr>`)
                        .join("");
                    return `
                        <article class="blk">
                            <h4>${escapeHtml(section || "General")}</h4>
                            <p>${sqs.length} questions (${secPct}% within ${escapeHtml(subject)})</p>
                            <table><thead><tr><th>Micro-topic</th><th>Count</th></tr></thead><tbody>${microRows}</tbody></table>
                        </article>
                    `;
                }).join("");
            return `
                <section class="subject">
                    <h3>${escapeHtml(subject)}</h3>
                    <p>${qs.length} questions (${pct}% of total)</p>
                    ${sectionRows}
                </section>
            `;
        }).join("");

    const html = `<!DOCTYPE html>
<html><head><meta charset="UTF-8"><title>PYQ Subject Distribution Full Report</title>
<style>
@page { size:A4; margin:10mm; }
body { font-family: Inter, Arial, sans-serif; color:#0f172a; margin:0; }
.wrap { padding:8px; }
h1 { margin:0 0 6px; font-size:20px; }
h2 { margin:18px 0 8px; font-size:16px; }
h3 { margin:14px 0 6px; font-size:15px; color:#4c1d95; }
h4 { margin:10px 0 4px; font-size:13px; color:#6d28d9; }
p { margin:0 0 8px; font-size:12px; color:#334155; }
.subject { border:1px solid #ddd6fe; border-radius:10px; padding:10px; margin-bottom:12px; background:#faf5ff; page-break-inside:avoid; }
.blk { border:1px solid #ede9fe; border-radius:8px; padding:8px; margin:8px 0; background:#ffffff; page-break-inside:avoid; }
table { width:100%; border-collapse:collapse; margin-top:6px; font-size:11px; }
th, td { border:1px solid #e2e8f0; padding:6px 8px; }
th { background:#f5f3ff; text-align:left; }
</style></head>
<body><div class="wrap">
<h1>PYQ Subject Distribution Full Report</h1>
<p>${escapeHtml(state.pyqAnalysisProvider || "UPSC CSE")} • ${escapeHtml(state.pyqAnalysisSection || "-")} • ${escapeHtml(state.pyqAnalysisPaper || "-")}</p>
<p>Year Range: ${escapeHtml(yearRangeLabel)} • Total Questions: ${total}</p>
<h2>Subject-wise Summary</h2>
${subjectCards}
</div></body></html>`;
    printHtmlInFrame(html);
}

function downloadIncorrectQuestionsFile() {
    const record = selectedAnalyticsAttempt();
    const html = buildIncorrectQuestionsDownload(record);
    const safeTitle = (record?.test?.title || "incorrect-questions")
        .replace(/[^\w\s-]+/g, "")
        .trim()
        .replace(/\s+/g, "-")
        .toLowerCase();
    const blob = new Blob([html], { type: "text/html;charset=utf-8" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `${safeTitle || "incorrect-questions"}-review.html`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
}

