                            <button class="ghost-btn small danger-btn" type="button" id="bulkDeleteAdvancedSearchBtn" ${!state.adminAdvancedSearchSelections.length ? "disabled" : ""}>Delete Selected (${state.adminAdvancedSearchSelections.length})</button>
