    document.querySelectorAll("[data-spaced-schedule]").forEach((button) => button.addEventListener("click", async () => {
        const questionId = button.dataset.questionId;
        const testId = button.dataset.testId;
        const days = Number(button.dataset.spacedSchedule);
        if (!questionId || !testId || !days) return;
        const question = (state.spacedSession?.questions || []).find((item) => item.id === questionId);
        await updateQuestionStateByTest(testId, questionId, {
            spacedRevision: {
                ...(question?.spacedRevision || {}),
                ...createSpacedSchedule(days)
            }
        });
        if (state.spacedSession?.questions?.length) {
            state.spacedSession = {
                ...state.spacedSession,
                questions: state.spacedSession.questions.filter((item) => item.id !== questionId)
            };
            state.spacedSessionIndex = Math.min(state.spacedSessionIndex, Math.max(state.spacedSession.questions.length - 2, 0));
            if (!state.spacedSession.questions.length) {
                state.spacedSession = null;
                state.spacedSessionIndex = 0;
            }
        }
        state.spacedRevealAnswer = false;
        state.quietRender = true;
        renderApp();
    }));
