    document.getElementById("launchStartBtn")?.addEventListener("click", async () => {
        const selected = activeTest();
        if (!selected?.id) return;
        const test = await ensureTestQuestionsLoaded(selected.id);
        if (!test?.questions?.length) {
            setAuthNotice("Questions for this test are still loading. Please try again.", "warning");
            renderApp();
            return;
        }
        const existingDraft = await resumeDraftWithCloudFallback(test.id);
        const fallbackNameParts = [
            testPrimarySubjectValue(test) || testPaperSubjectValue(test) || state.selectedSubject || state.practiceTestPaperSubject || "Mixed Subject",
            testPrimarySectionGroupValue(test, testPrimarySubjectValue(test)) || testPaperSectionGroupValue(test) || state.practiceTestPaperSectionGroup || "",
            state.selectedSectionGroup && state.selectedSectionGroup !== "All" ? state.selectedSectionGroup : "",
            state.practiceTopicSectionGroup && state.practiceTopicSectionGroup !== "All" ? state.practiceTopicSectionGroup : "",
            state.practiceMicroTopicFilters?.length ? state.practiceMicroTopicFilters.slice(0, 2).join(", ") : ""
        ].filter(Boolean);
        const suggestedName = fallbackNameParts.join(" - ") || test.title || "Practice Test";
        const customName = window.prompt("Enter a custom test name (optional):", suggestedName);
        if (customName === null) return;
        const resolvedTitle = resolveAttemptTitleWithCustom([
            testPrimarySubjectValue(test) || testPaperSubjectValue(test) || test.subject || state.selectedSubject || state.practiceTestPaperSubject || "Mixed Subject",
            testPrimarySectionGroupValue(test, testPrimarySubjectValue(test)) || testPaperSectionGroupValue(test) || state.practiceTestPaperSectionGroup || "",
            state.selectedSectionGroup && state.selectedSectionGroup !== "All" ? state.selectedSectionGroup : "",
            state.practiceTopicSectionGroup && state.practiceTopicSectionGroup !== "All" ? state.practiceTopicSectionGroup : "",
            state.practiceMicroTopicFilters?.length ? state.practiceMicroTopicFilters.slice(0, 2).join(", ") : "",
            state.selectedSeries && state.selectedSeries !== "All Collections" ? state.selectedSeries : ""
        ], customName);
        state.activeAttempt = existingDraft || createAttemptDraft(
            { ...test, title: resolvedTitle },
            { explanationMode: "ask", timerMode: "ask", timerMinutes: test.defaultMinutes }
        );
        clearAuthNotice();
        startTimerIfNeeded();
        state.submitConfirmOpen = false;
        state.paletteOpen = false;
        state.currentView = "practice";
        persistActiveAttemptDraft();
        renderApp();
    });
