    // Save-to-notebook popup bullet editor: keep draft state in sync while typing.
    document.querySelectorAll("[data-save-note-bullet]").forEach((box) => box.addEventListener("input", (event) => {
        const idx = Number.parseInt(event.target.dataset.saveNoteBullet, 10);
        if (!Number.isFinite(idx)) return;
        const drafts = Array.isArray(state.saveNoteBulletDrafts) ? [...state.saveNoteBulletDrafts] : [];
        while (drafts.length <= idx) drafts.push("");
        drafts[idx] = event.target.value;
        state.saveNoteBulletDrafts = drafts;
    }));

    // Add to Notebook (Save highlighted selection to Notes)
    document.querySelectorAll("[data-add-to-notebook]").forEach((btn) => btn.addEventListener("click", () => {
        if (!isLoggedIn()) {
            setAuthNotice("Please log in to save highlights to Notes.", "warning");
            renderApp();
            return;
        }
        const questionId = btn.dataset.addToNotebook || "";
        const selectionText = captureSelectedText();
        const text = selectionText || state.selectedText || "";
        if (!text || text.trim().length < 5) {
            setAuthNotice("Highlight some explanation text first, then click “Add to Notebook”.", "warning");
            renderApp();
            return;
        }
        const sessionQuestion = currentStudyQuestions().find((q) => q.id === questionId);
        const testId = sessionQuestion?.__studyTestId || sessionQuestion?.testId || state.selectedTestId || state.activeTestId || null;
        openSaveToNotePanel(text.trim(), {
            type: "question",
            questionId,
            testId
        });
    }));

    // Save note button handler
    document.querySelectorAll("[data-save-note]").forEach((btn) => btn.addEventListener("click", async (event) => {
        const questionId = event.target.dataset.saveNote;
        const sessionQuestion = currentStudyQuestions().find((q) => q.id === questionId);
        if (!sessionQuestion) return;

        const draftNote = state.studyNoteDrafts[questionId] ?? sessionQuestion.note ?? "";

        try {
            await updateStudyQuestionState(questionId, {
                note: draftNote,
                savedFolders: sessionQuestion.savedFolders || []
            });
            setAuthNotice("Note saved successfully.", "success");
        } catch (error) {
            console.error("Failed to save note:", error);
            setAuthNotice("Failed to save note. Please try again.", "error");
        }
    }));

    document.querySelectorAll("[data-study-folder]").forEach((select) => select.addEventListener("change", async (event) => {
        const questionId = event.target.dataset.studyFolder;
        const selectedFolder = event.target.value;
        const sessionQuestion = currentStudyQuestions().find((question) => question.id === questionId);
        if (!sessionQuestion) return;
        
        // Only save if a folder is actually selected (not empty)
        if (!selectedFolder) {
            state.studyFolderDrafts = {
                ...state.studyFolderDrafts,
                [questionId]: ""
            };
            return;
        }
        
        // Check if already saved to this folder to avoid duplicates
        const currentFolders = Array.isArray(sessionQuestion.savedFolders) ? sessionQuestion.savedFolders : [];
        if (currentFolders.includes(selectedFolder)) {
            // Already saved, just update draft
            state.studyFolderDrafts = {
                ...state.studyFolderDrafts,
                [questionId]: selectedFolder
            };
            return;
        }
        
        // Save immediately to selected folder
        const nextFolders = [...new Set([...currentFolders, selectedFolder])];
        await updateStudyQuestionState(questionId, {
            note: state.studyNoteDrafts[questionId] ?? sessionQuestion.note ?? "",
            savedFolders: nextFolders
        });
        
        // Update draft to reflect current selection
        state.studyFolderDrafts = {
            ...state.studyFolderDrafts,
            [questionId]: selectedFolder
        };
        
        state.quietRender = true;
        renderApp();
    }));
    
    // Handle new folder creation
    document.querySelectorAll("[data-study-folder]").forEach((select) => {
        select.addEventListener("change", async (event) => {
            const questionId = event.target.dataset.studyFolder;
            const selectedValue = event.target.value;
            const newFolderInput = document.querySelector(`[data-study-new-folder="${questionId}"]`);
            
            if (selectedValue === "__create_new__") {
                // Show input field for new folder name
                event.target.setAttribute("data-new-folder-mode", "true");
                if (newFolderInput) {
                    newFolderInput.style.display = "block";
                    newFolderInput.focus();
                }
                return;
            } else {
                // Hide input field if not creating new folder
                event.target.setAttribute("data-new-folder-mode", "false");
                if (newFolderInput) {
                    newFolderInput.style.display = "none";
                    newFolderInput.value = "";
                }
            }
        });
    });
    
    // Handle new folder input
    document.querySelectorAll("[data-study-new-folder]").forEach((input) => {
        input.addEventListener("keydown", async (event) => {
            if (event.key === "Enter") {
                event.preventDefault();
                await createNewFolderAndSave(event.target);
            } else if (event.key === "Escape") {
                // Cancel folder creation
                const questionId = event.target.dataset.studyNewFolder;
                const select = document.querySelector(`[data-study-folder="${questionId}"]`);
                event.target.style.display = "none";
                event.target.value = "";
                if (select) {
                    select.value = "";
                    select.setAttribute("data-new-folder-mode", "false");
                }
            }
        });
        
        input.addEventListener("blur", async (event) => {
            // Create folder if input has content and loses focus
            if (event.target.value.trim()) {
                await createNewFolderAndSave(event.target);
            }
        });
    });
    
    async function createNewFolderAndSave(input) {
        const questionId = input.dataset.studyNewFolder;
        const folderName = input.value.trim();
        const select = document.querySelector(`[data-study-folder="${questionId}"]`);
        
        if (!folderName) return;
        
        // Check if folder already exists
        if (state.userFolders.includes(folderName)) {
            setAuthNotice(`Folder "${folderName}" already exists.`, "warning");
            return;
        }
        
        try {
            // Create new folder
            state.userFolders = [...state.userFolders, folderName];
            console.log('Creating new folder:', folderName, 'Updated folders:', state.userFolders);
            
            // Save to user settings with explicit real-time update
            await saveUserSettings(state.currentUser.uid, { folders: state.userFolders });
            
            // Force a small delay to ensure real-time sync has time to propagate
            await new Promise(resolve => setTimeout(resolve, 100));
            
            // Update select with new folder
            if (select) {
                select.value = folderName;
                select.setAttribute("data-new-folder-mode", "false");
                input.style.display = "none";
                input.value = "";
                
                // Trigger the folder save logic
                const changeEvent = new Event("change", { bubbles: true });
                select.dispatchEvent(changeEvent);
            }
            
            setAuthNotice(`Folder "${folderName}" created successfully.`, "success");
        } catch (error) {
            console.error('Error creating new folder:', error);
            setAuthNotice(`Failed to create folder "${folderName}". Please try again.`, "error");
        }
        state.quietRender = true;
        renderApp();
    }
    
