    document.querySelectorAll("[data-tag-duplicate]").forEach((button) => button.addEventListener("click", async () => {
        const tagName = button.dataset.tagDuplicate;
        const newTagName = prompt(`Duplicate "${tagName}" as:`, `${tagName} Copy`);
        if (!newTagName || newTagName === tagName) return;
        if (state.userTags.includes(newTagName)) {
            setAuthNotice(`Tag "${newTagName}" already exists.`, "error");
            return;
        }
        state.userTags.push(newTagName);
        await persistUserSettingsPatch({ tags: state.userTags });
        const taggedQuestions = questionsWithTag(tagName);
        for (const q of taggedQuestions) {
            const currentTags = q.reviewTags || [];
            if (!currentTags.includes(newTagName)) {
                await updateStoredReviewQuestionState(q.__tagTestId, q.id, (question) => ({
                    reviewTags: [...(question.reviewTags || []), newTagName]
                }));
            }
        }
        state.selectedTagName = newTagName;
        state.quietRender = true;
        renderApp();
    }));
    
    document.querySelectorAll("[data-tag-rename]").forEach((button) => button.addEventListener("click", async () => {
        const oldName = button.dataset.tagRename;
        const newName = prompt(`Rename "${oldName}" to:`, oldName);
        if (!newName || newName === oldName) return;
        if (state.userTags.includes(newName)) {
            setAuthNotice(`Tag "${newName}" already exists.`, "error");
            return;
        }
        state.userTags = state.userTags.map(t => t === oldName ? newName : t);
        await persistUserSettingsPatch({ tags: state.userTags });
        const taggedQuestions = questionsWithTag(oldName);
        for (const q of taggedQuestions) {
            const currentTags = q.reviewTags || [];
            const newTags = currentTags.map(t => t === oldName ? newName : t);
            await updateStoredReviewQuestionState(q.__tagTestId, q.id, (question) => ({
                reviewTags: newTags
            }));
        }
        if (state.selectedTagName === oldName) {
            state.selectedTagName = newName;
        }
        state.quietRender = true;
        renderApp();
    }));
    
    document.querySelectorAll("[data-tag-delete]").forEach((button) => button.addEventListener("click", async () => {
        const tagName = button.dataset.tagDelete;
        if (!confirm(`Delete tag "${tagName}"? This will remove the tag from all questions.`)) return;
        state.userTags = state.userTags.filter(t => t !== tagName);
        await persistUserSettingsPatch({ tags: state.userTags });
        const taggedQuestions = questionsWithTag(tagName);
        for (const q of taggedQuestions) {
            const currentTags = q.reviewTags || [];
            const newTags = currentTags.filter(t => t !== tagName);
            await updateStoredReviewQuestionState(q.__tagTestId, q.id, (question) => ({
                reviewTags: newTags
            }));
        }
        if (state.selectedTagName === tagName) {
            state.selectedTagName = "";
        }
        state.quietRender = true;
        renderApp();
    }));
    
