    document.querySelectorAll("[data-admin-inspection-microtopic]").forEach((select) => select.addEventListener("change", async (event) => {
        if (!isAdminUser()) return;
        const testId = event.target.dataset.adminInspectionTest || state.selectedTestId;
        const test = sampleTests.find((item) => item.id === testId) || activeTest();
        const questionId = event.target.dataset.adminInspectionMicrotopic;
        const microTopic = event.target.value;
        const targetQuestion = test?.questions?.find((question) => question.id === questionId);
        if (!test || !targetQuestion) return;
        const patch = { microTopic };
        const nextTest = updateTestInMemory(test.id, (current) => ({
            ...current,
            questions: current.questions.map((question) => question.id === questionId ? { ...question, ...patch } : question)
        }));
        saveAdminQuestionMeta(test.id, questionId, patch);
        await saveFullTest(nextTest);
        if (state.adminEditorQuestionId === questionId) {
            ensureAdminSelectionState();
        }
        setAdminNotice(`Saved micro-topic for Q${targetQuestion.questionNumber}.`);
        state.quietRender = true;
        renderApp();
    }));
    document.querySelectorAll("[data-admin-inspection-section]").forEach((select) => select.addEventListener("change", async (event) => {
        if (!isAdminUser()) return;
        const testId = event.target.dataset.adminInspectionTest || state.selectedTestId;
        const test = sampleTests.find((item) => item.id === testId) || activeTest();
        const questionId = event.target.dataset.adminInspectionSection;
        const sectionGroup = event.target.value || null;
        const targetQuestion = test?.questions?.find((question) => question.id === questionId);
        if (!test || !targetQuestion) return;
        const allowedMicroTopics = taxonomyMicroTopics(questionSubjectValue(targetQuestion, test), sectionGroup);
        const nextMicroTopic = allowedMicroTopics.includes(targetQuestion.microTopic) ? targetQuestion.microTopic : (allowedMicroTopics[0] || "");
        const patch = {
            sectionGroup,
            ...(nextMicroTopic ? { microTopic: nextMicroTopic } : {})
        };
        const nextTest = updateTestInMemory(test.id, (current) => ({
            ...current,
            questions: current.questions.map((question) => question.id === questionId ? { ...question, ...patch } : question)
        }));
        saveAdminQuestionMeta(test.id, questionId, patch);
        await saveFullTest(nextTest);
        if (state.selectedTestId === test.id) {
            ensureAdminSelectionState();
        }
        setAdminNotice(`Saved section group for Q${targetQuestion.questionNumber}.`);
        state.quietRender = true;
        renderApp();
    }));
