    document.getElementById("adminBulkToggleVisibleBtn")?.addEventListener("click", async () => {
        await prepareAdminBulkData();
        const visibleIds = adminBulkQuestionPool().map((question) => question.id);
        const allSelected = visibleIds.length && visibleIds.every((id) => state.adminBulkSelectionIds.includes(id));
        state.adminBulkSelectionIds = allSelected ? state.adminBulkSelectionIds.filter((id) => !visibleIds.includes(id)) : [...new Set([...state.adminBulkSelectionIds, ...visibleIds])];
        state.quietRender = true;
        renderApp();
    });
    document.getElementById("adminBulkApplyBtn")?.addEventListener("click", async () => {
        if (!isAdminUser()) return;
        await prepareAdminBulkData();
        const targetRows = adminBulkQuestionPool().filter((question) => state.adminBulkSelectionMode === "all" || state.adminBulkSelectionIds.includes(question.id));
        if (!targetRows.length) return;
        const grouped = new Map();
        targetRows.forEach((question) => {
            const current = grouped.get(question.__bulkTestId) || [];
            current.push(question.id);
            grouped.set(question.__bulkTestId, current);
        });
        for (const [testId, questionIds] of grouped.entries()) {
            const currentTest = sampleTests.find((item) => item.id === testId);
            if (!currentTest) continue;
            const patch = {
                sectionGroup: state.adminBulkTargetSectionGroup || null,
                microTopic: state.adminBulkTargetMicroTopic || undefined
            };
            const nextTest = updateTestInMemory(testId, (current) => ({
                ...current,
                questions: current.questions.map((question) => questionIds.includes(question.id) ? {
                    ...question,
                    ...(patch.microTopic !== undefined ? { microTopic: patch.microTopic } : {}),
                    sectionGroup: patch.sectionGroup
                } : question)
            }));
            questionIds.forEach((questionId) => saveAdminQuestionMeta(testId, questionId, {
                ...(patch.microTopic !== undefined ? { microTopic: patch.microTopic } : {}),
                sectionGroup: patch.sectionGroup
            }));
            await saveFullTest(nextTest);
        }
        setAdminNotice(`Bulk-updated ${targetRows.length} question(s).`);
        state.quietRender = true;
        renderApp();
    });

