        await prepareAdminBulkData();
        const visibleIds = adminSourceCleanupPool().map((question) => question.id);
        const allSelected = visibleIds.length && visibleIds.every((id) => state.adminBulkSelectionIds.includes(id));
        state.adminBulkSelectionIds = allSelected
            ? state.adminBulkSelectionIds.filter((id) => !visibleIds.includes(id))
            : [...new Set([...state.adminBulkSelectionIds, ...visibleIds])];
        state.quietRender = true;
