    document.getElementById("dupPreviewMergeBtn")?.addEventListener("click", () => {
        const groups = state.duplicateManagerResults || [];
        const groupsToPreview = state.duplicateManagerSelectedPairs.map((index) => groups[index]).filter(Boolean);

        if (!groupsToPreview.length) {
            setAdminNotice("No groups selected for preview.");
            return;
        }

        openDuplicateGroupsPreviewTab(groupsToPreview);
    });

    document.querySelectorAll("[data-group-index]").forEach((checkbox) => {
        checkbox.addEventListener("change", (event) => {
            const index = parseInt(event.target.dataset.groupIndex, 10);
            if (event.target.checked) {
                state.duplicateManagerSelectedPairs.push(index);
            } else {
                state.duplicateManagerSelectedPairs = state.duplicateManagerSelectedPairs.filter((i) => i !== index);
            }
            state.quietRender = true;
            renderApp();
        });
    });

    document.getElementById("dupMergeSelectedBtn")?.addEventListener("click", async () => {
        if (!isAdminUser() || !state.duplicateManagerSelectedPairs.length) return;
        const groups = state.duplicateManagerResults || [];
        const groupsToMerge = state.duplicateManagerSelectedPairs.map((index) => groups[index]).filter(Boolean);
        
        if (!groupsToMerge.length) return;
        
        const totalQuestions = groupsToMerge.reduce((sum, g) => sum + g.questions.length, 0);
        const confirmed = window.confirm(`Merge ${groupsToMerge.length} duplicate groups (${totalQuestions} total questions) into canonical UPSC/CSE questions?`);
        if (!confirmed) return;
        
        const mergeMode = document.getElementById("dupMergeMode")?.value || "hard-delete";
        const defaultExplanation = document.getElementById("dupDefaultExplanation")?.value || "combined";
        const vaultProv = resolveCanonicalVaultProvider(null);
        saveLastMergeBackupPayload(captureMergeBackup(groupsToMerge, vaultProv));
        
        let mergedCount = 0;
        const affectedTestIds = new Set();
        for (const group of groupsToMerge) {
            await mergeDuplicateGroup(group, mergeMode, defaultExplanation, null, vaultProv);
            mergedCount++;
            (group.questions || []).forEach((q) => q?.testId && affectedTestIds.add(q.testId));
        }

        // Persist changes so merges survive refresh.
        try {
            const sourceTests = Array.from(affectedTestIds).map((id) => sampleTests.find((t) => t.id === id)).filter(Boolean);
            for (const t of sourceTests) {
                await saveFullTest(t);
            }
            const vaultStores = canonicalStoreTests(vaultProv);
            for (const t of vaultStores) {
                await saveFullTest(t);
            }
        } finally {
            // Ensure search/cache refresh sees latest canonical + virtual links
            try {
                localStorage.removeItem("upscVault_allQuestions");
            } catch {}
            try {
                const vaultIds = canonicalStoreTests(vaultProv).map((t) => t.id);
                await removeQuestionsFromCache([...affectedTestIds, ...vaultIds]);
            } catch {}
            practiceSearchCacheKey = null;
            practiceSearchCacheResults = [];
            practiceSearchDataVersion++;
        }
        
        setAdminNotice(`${mergedCount} duplicate groups merged successfully into canonical questions.`);
        state.duplicateManagerSelectedPairs = [];
        state.duplicateManagerReady = false;
        state.quietRender = false;
        renderApp();
    });

