function getFlashcardSubjectIcon(sub) {
    const icons = {
        "History": "fa-history",
        "Polity": "fa-gavel",
        "Economy": "fa-chart-line",
        "Geography": "fa-globe-asia",
        "Science": "fa-microscope",
        "Environment": "fa-leaf",
        "Art & Culture": "fa-synagogue",
        "CSAT": "fa-calculator",
        "Current Affairs": "fa-newspaper",
        "Society": "fa-users"
    };
    const iconClass = icons[sub] || "fa-book";
    return `<i class="fas ${iconClass}" style="width: 20px; text-align: center; color: var(--accent);"></i>`;
}


