async function saveFlashcardSettings(intervals) {
    if (!state.currentUser) return;
    
    try {
        await saveUserSettings(state.currentUser.uid, { deckIntervals: intervals });
        state.deckIntervals = intervals;
        setAuthNotice("Interval preferences updated successfully.", "success");
        state.flashcardSettingsOpen = false;
        renderApp();
    } catch (e) {
        console.error("Failed to save flashcard settings:", e);
        setAuthNotice("Failed to save preferences. Please try again.", "error");
    }
}

let __studentSyncUiTimer = null;
function isActivelyEditingFormField() {
    const ae = document.activeElement;
    if (!ae) return false;
    // Keep open form controls stable while background sync updates UI.
    if (ae.matches?.("input, textarea, select")) return true;
    if (ae.isContentEditable) return true;
    return false;
}
function hasLiveTextSelection() {
    const s = window.getSelection?.();
    if (!s) return false;
    return !s.isCollapsed && String(s.toString() || "").trim().length > 0;
}
function touchUiInteractionLock(ms = 1200) {
    uiInteractionLockUntil = Math.max(uiInteractionLockUntil, Date.now() + ms);
}
initStudentSync({
    setStatus(patch) {
        state.studentSync = { ...state.studentSync, ...patch };
        if (__studentSyncUiTimer) clearTimeout(__studentSyncUiTimer);
        // Avoid resetting in-progress typing by not forcing full rerenders while user edits controls.
        const delayMs = isActivelyEditingFormField() ? 1200 : 220;
        __studentSyncUiTimer = setTimeout(() => {
            __studentSyncUiTimer = null;
            if (isActivelyEditingFormField()) return;
            renderApp();
        }, delayMs);
    }
});






// Mobile UI Hotfix: Keep text selection persistently updated for notebook insertion
document.addEventListener('selectionchange', () => {
    const s = window.getSelection?.();
    if (s && s.toString().trim().length > 5) {
        state.selectedText = s.toString().trim().replace(/\s+/g, ' ');
        touchUiInteractionLock(1500);
    }
});
document.addEventListener("pointerdown", (event) => {
    const t = event.target;
    if (t?.closest?.("input, textarea, select, [contenteditable='true'], [contenteditable=''], .search-input-wrap")) {
        touchUiInteractionLock(1500);
    }
}, true);
document.addEventListener("keydown", (event) => {
    const t = event.target;
    if (t?.closest?.("input, textarea, select, [contenteditable='true'], [contenteditable='']")) {
        touchUiInteractionLock(1500);
    }
}, true);

document.addEventListener("contextmenu", (event) => {
    const row = event.target?.closest?.("[data-notes-node]");
    if (!row || state.currentView !== "notes") return;
    event.preventDefault();
    const nodeId = String(row.dataset.notesNode || "");
    if (!nodeId) return;
    state.notesTreeSelectedNodeId = nodeId;
    state.notesTreeContextMenu = { nodeId, x: event.clientX, y: event.clientY };
    state.quietRender = true;
    renderApp();
});



